(11, 'manage_departments', 'Create and manage departments', '2025-03-23 06:16:07'),
(12, 'manage_permissions', 'Assign and modify permissions', '2025-03-23 06:16:07');
INSERT INTO `questions` (`id`, `quiz_id`, `question_text`, `explanation`, `created_at`, `updated_at`) VALUES
(26, 3, 'คำใดต่อไปนี้เป็นคำสมาส?', '“กินข้าว” เป็นคำสมาส  เกิดจากคำว่า กิน + ข้าว รวมกันแล้วความหมายเปลี่ยนไป', '2025-03-12 14:35:08', '2025-03-12 14:35:08'),
(27, 3, 'คำใดต่อไปนี้เป็นคำซ้อน?', '“บ้านช่อง” เป็นคำซ้อน เกิดจากคำพ้องความหมายหรือใกล้เคียงกันมาซ้อนกัน', '2025-03-12 14:35:08', '2025-03-12 14:35:08'),
(28, 3, 'ข้อใดใช้ลักษณะนามไม่ถูกต้อง', 'ลักษณะนามของปลา คือ ตัว หรือ หาง ไม่ใช่ ฝูง (ฝูง ใช้กับกลุ่มของปลา)', '2025-03-12 14:35:08', '2025-03-12 14:35:08'),
(29, 3, 'คำว่า “วิทยาศาสตร์” มีที่มาจากภาษาใด', 'วิทยาศาสตร์ มาจากภาษาสันสกฤต', '2025-03-12 14:35:08', '2025-03-12 14:35:08'),
(30, 3, 'ข้อใดเป็นคำวิเศษณ์?', '“สวย” เป็นคำวิเศษณ์  ใช้ขยายคำนาม', '2025-03-12 14:35:08', '2025-03-12 14:35:08'),
(31, 3, 'สำนวน “น้ำท่วมทุ่ง ผักบุ้งโหรงเหรง” หมายความว่าอย่างไร', 'น้ำท่วมทุ่ง ผักบุ้งโหรงเหรง หมายถึง พูดมากแต่ได้สาระน้อย', '2025-03-12 14:35:08', '2025-03-12 14:35:08'),
(32, 3, 'คำราชาศัพท์ข้อใดหมายถึง “กิน”', 'เสวย เป็นคำราชาศัพท์ หมายถึง กิน', '2025-03-12 14:35:08', '2025-03-12 14:35:08'),
(33, 3, 'ข้อใดสะกดถูกต้อง', 'คำว่า ทรัพย์สิน สะกดด้วย ย และ ณ', '2025-03-12 14:35:08', '2025-03-12 14:35:08'),
(34, 3, 'คำใดมีเสียงวรรณยุกต์ตรี', 'คำว่า ก๋วยเตี๋ยว มีเสียงวรรณยุกต์ตรี  คือเสียงเตี๋ยว', '2025-03-12 14:35:08', '2025-03-12 14:35:08'),
(35, 3, 'คำว่า “อนุญาต”  มีความหมายตรงข้ามกับคำใด', 'อนุญาต หมายถึง อนุมัติ, ยินยอม ให้ทำ ส่วน ห้าม มีความหมายตรงข้าม', '2025-03-12 14:35:08', '2025-03-12 14:35:08'),
(36, 4, 'หลักการสำคัญของการสื่อสารการตลาดแบบบูรณาการ (IMC) คืออะไร?', 'IMC มุ่งเน้นการส่งสารที่สอดคล้องกันผ่านทุกช่องทาง เพื่อสร้างภาพลักษณ์แบรนด์ที่ชัดเจนและแข็งแกร่ง', '2025-03-12 14:43:23', '2025-03-12 14:43:23'),
(37, 4, 'AIDA Model ในการสื่อสารการตลาด หมายถึงอะไร?', 'AIDA Model อธิบายขั้นตอนการตอบสนองของผู้บริโภคต่อการสื่อสารการตลาด ตั้งแต่การดึงดูดความสนใจจนถึงการตัดสินใจซื้อ', '2025-03-12 14:43:23', '2025-03-12 14:43:23'),
(38, 4, 'การตลาดแบบดิจิทัล (Digital Marketing) มีข้อดีอย่างไร เมื่อเทียบกับการตลาดแบบดั้งเดิม?', 'Digital Marketing ช่วยให้สามารถกำหนดกลุ่มเป้าหมายได้อย่างเฉพาะเจาะจง และติดตามวัดผลได้อย่างมีประสิทธิภาพมากกว่าการตลาดแบบดั้งเดิม', '2025-03-12 14:43:23', '2025-03-12 14:43:23'),
(39, 4, 'SEO ย่อมาจากอะไร?', 'SEO คือ Search Engine Optimization ซึ่งเป็นการปรับแต่งเว็บไซต์ให้ติดอันดับต้นๆ ในผลการค้นหาของ Search Engine', '2025-03-12 14:43:23', '2025-03-12 14:43:23'),
(40, 4, 'อะไรคือตัวอย่างของ KPI ในการตลาด?', 'KPI คือ Key Performance Indicator ซึ่งเป็นตัวชี้วัดความสำเร็จของการดำเนินงาน ตัวอย่าง KPI ในการตลาด เช่น ยอดขาย จำนวนผู้เข้าชมเว็บไซต์ และอัตราการมีส่วนร่วม', '2025-03-12 14:43:23', '2025-03-12 14:43:23'),
(41, 4, 'Content Marketing คืออะไร?', 'Content Marketing เน้นการสร้างเนื้อหาที่เป็นประโยชน์ต่อกลุ่มเป้าหมาย เพื่อสร้างความสัมพันธ์และดึงดูดให้เกิด Conversion', '2025-03-12 14:43:23', '2025-03-12 14:43:23'),
(42, 4, 'SWOT analysis ประกอบด้วยอะไรบ้าง?', 'SWOT analysis เป็นการวิเคราะห์จุดแข็ง จุดอ่อน โอกาส และภัยคุกคาม', '2025-03-12 14:43:23', '2025-03-12 14:43:23'),
(43, 4, 'CRM ย่อมาจากอะไร?', 'CRM คือ Customer Relationship Management ซึ่งเป็นระบบการจัดการความสัมพันธ์กับลูกค้า', '2025-03-12 14:43:23', '2025-03-12 14:43:23'),
(44, 4, 'Public Relations (PR) มีบทบาทสำคัญอย่างไรใน การสื่อสารและการตลาด?', 'PR มุ่งเน้นการสร้างและรักษาภาพลักษณ์ที่ดีขององค์กรต่อสาธารณะ', '2025-03-12 14:43:23', '2025-03-12 14:43:23'),
(45, 4, 'การตลาดแบบ Influencer Marketing คืออะไร?', 'Influencer Marketing ใช้บุคคลที่มีผู้ติดตามจำนวนมากและมีอิทธิพลต่อความคิดของกลุ่มเป้าหมาย ในการโปรโมตสินค้าหรือบริการ', '2025-03-12 14:43:23', '2025-03-12 14:43:23'),
(46, 4, 'การตลาดแบบบูรณาการ (Integrated Marketing Communication - IMC) หมายถึงอะไร', 'IMC เน้นการใช้เครื่องมือสื่อสารการตลาดหลายช่องทางร่วมกัน เพื่อสร้างภาพลักษณ์และส่งสารที่สอดคล้องกันให้กับกลุ่มเป้าหมาย', '2025-03-12 14:43:23', '2025-03-12 14:43:23'),
(47, 4, 'อะไรคือข้อแตกต่างที่สำคัญระหว่าง Public Relations และ Advertising?', 'PR สร้างและรักษาความสัมพันธ์ที่ดีกับสาธารณะ ในขณะที่ Advertising จ่ายเงินเพื่อโปรโมตสินค้าหรือบริการ', '2025-03-12 14:43:23', '2025-03-12 14:43:23'),
(48, 4, 'AIDA Model ในการสื่อสารการตลาดประกอบด้วยอะไรบ้าง', 'AIDA ย่อมาจาก Attention, Interest, Desire, Action ซึ่งเป็นขั้นตอนการโน้มน้าวใจลูกค้า', '2025-03-12 14:43:23', '2025-03-12 14:43:23'),
(49, 4, 'การตลาดแบบดิจิทัล (Digital Marketing) คืออะไร', 'Digital Marketing ใช้ช่องทางดิจิทัลเช่น เว็บไซต์, โซเชียลมีเดีย, อีเมล ในการทำการตลาด', '2025-03-12 14:43:23', '2025-03-12 14:43:23'),
(50, 4, 'KPI ย่อมาจากอะไร', 'KPI ย่อมาจาก Key Performance Indicator ซึ่งเป็นตัวชี้วัดความสำเร็จของเป้าหมาย', '2025-03-12 14:43:23', '2025-03-12 14:43:23'),
(51, 4, 'SEO ย่อมาจากอะไร', 'SEO คือ Search Engine Optimization ซึ่งเป็นการปรับปรุงเว็บไซต์ให้ติดอันดับต้นๆ ในผลการค้นหา', '2025-03-12 14:43:23', '2025-03-12 14:43:23'),
(52, 4, 'Content Marketing คืออะไร', 'Content Marketing เน้นการสร้างเนื้อหาที่เป็นประโยชน์ต่อกลุ่มเป้าหมาย เพื่อสร้างความสัมพันธ์และดึงดูดลูกค้า', '2025-03-12 14:43:23', '2025-03-12 14:43:23'),
(53, 4, 'SWOT analysis ประกอบด้วยอะไร', 'SWOT analysis เป็นการวิเคราะห์จุดแข็ง จุดอ่อน โอกาส และภัยคุกคาม', '2025-03-12 14:43:23', '2025-03-12 14:43:23'),
(54, 4, 'อะไรคือความสำคัญของการวิจัยตลาด (Market Research)', 'การวิจัยตลาดช่วยให้เข้าใจลูกค้าและตลาด เพื่อวางแผนการตลาดได้อย่างมีประสิทธิภาพ', '2025-03-12 14:43:23', '2025-03-12 14:43:23'),
(55, 4, 'Brand Loyalty หมายถึงอะไร', 'Brand Loyalty คือความผูกพันและความภักดีที่ลูกค้ามีต่อแบรนด์สินค้าหรือบริการ', '2025-03-12 14:43:23', '2025-03-12 14:43:23'),
(66, 6, 'Which of the following is NOT a fundamental force of nature?', 'Friction is a macroscopic force resulting from electromagnetic interactions between atoms, not a fundamental force.', '2025-03-13 01:48:48', '2025-03-13 01:48:48'),
(67, 6, 'What is the SI unit of electric current?', 'Ampere is the base SI unit for electric current.', '2025-03-13 01:48:48', '2025-03-13 01:48:48'),
(68, 6, 'The process of a solid changing directly to a gas is called:', 'Sublimation is the phase transition from solid directly to gas.', '2025-03-13 01:48:48', '2025-03-13 01:48:48'),
(69, 6, 'Which law of thermodynamics states that entropy of an isolated system can only increase over time?', 'The Second Law of Thermodynamics deals with entropy and its tendency to increase in isolated systems.', '2025-03-13 01:48:48', '2025-03-13 01:48:48'),
(70, 6, 'What is the chemical symbol for potassium?', 'K is the chemical symbol derived from the Latin word \'Kalium\'.', '2025-03-13 01:48:48', '2025-03-13 01:48:48'),
(71, 6, 'Which particle carries a negative charge?', 'Electrons are negatively charged subatomic particles.', '2025-03-13 01:48:48', '2025-03-13 01:48:48'),
(72, 6, 'What is the formula for kinetic energy?', 'Kinetic energy is equal to half the mass times the velocity squared.', '2025-03-13 01:48:48', '2025-03-13 01:48:48'),
(73, 6, 'Newton\'s First Law of Motion is also known as the law of:', 'Newton\'s First Law states that an object at rest stays at rest and an object in motion stays in motion with the same speed and in the same direction unless acted upon by an unbalanced force - this is the concept of inertia.', '2025-03-13 01:48:48', '2025-03-13 01:48:48'),
(74, 6, 'What is the pH of a neutral solution?', 'A neutral solution has a pH of 7.', '2025-03-13 01:48:48', '2025-03-13 01:48:48'),
(75, 6, 'Which of the following is an example of a vector quantity?', 'Velocity is a vector quantity because it has both magnitude (speed) and direction.', '2025-03-13 01:48:48', '2025-03-13 01:48:48'),
(76, 7, 'ระบบการสื่อสารประเภทสายของทหารกองทัพบกส่วนใหญ่ใช้สื่อกลางประเภทใด?', 'ระบบสายส่วนใหญ่ในกองทัพบกยังคงใช้สายทองแดง เนื่องจากความทนทานและใช้งานง่ายในภาคสนาม', '2025-03-13 01:54:39', '2025-03-13 01:54:39'),
(77, 7, 'ข้อใดเป็นข้อดีของการสื่อสารประเภทสาย?', 'การสื่อสารผ่านสายมีโอกาสถูกดักฟังน้อยกว่าการสื่อสารแบบไร้สาย', '2025-03-13 01:54:39', '2025-03-13 01:54:39'),
(78, 7, 'TA-312/PT เป็นอุปกรณ์ประเภทใดในการสื่อสารประเภทสาย?', 'TA-312/PT คือโทรศัพท์สนามที่ใช้ในการสื่อสารประเภทสาย', '2025-03-13 01:54:39', '2025-03-13 01:54:39'),
(79, 7, 'ข้อใดไม่ใช่ข้อเสียของการสื่อสารประเภทสาย?', 'การสื่อสารประเภทสายมีความคล่องตัวต่ำ เนื่องจากต้องใช้สายสื่อสาร', '2025-03-13 01:54:39', '2025-03-13 01:54:39'),
(80, 7, 'การต่อสายสื่อสารประเภทสาย ควรคำนึงถึงสิ่งใดเป็นสำคัญ?', 'ความปลอดภัยเป็นสิ่งสำคัญที่สุดในการต่อสายสื่อสาร เพื่อป้องกันอันตราย', '2025-03-13 01:54:39', '2025-03-13 01:54:39'),
(81, 7, 'สายคู่บิดเกลียว (Twisted Pair Cable) มีไว้เพื่อ?', 'การบิดเกลียวของสายคู่บิดเกลียวช่วยลดสัญญาณรบกวนจากภายนอก', '2025-03-13 01:54:39', '2025-03-13 01:54:39'),
(82, 7, 'ในการวางสายสื่อสารภาคสนาม ควรเลือกใช้สายประเภทใด?', 'สายสนาม WD-1/TT ถูกออกแบบมาให้ทนทานต่อสภาพแวดล้อมในภาคสนาม', '2025-03-13 01:54:39', '2025-03-13 01:54:39'),
(83, 7, 'อะไรคือความแตกต่างที่สำคัญระหว่างสาย Single-mode และ Multi-mode fiber optic?', 'ขนาดของแกนกลางเป็นความแตกต่างที่สำคัญระหว่างสาย Single-mode และ Multi-mode', '2025-03-13 01:54:39', '2025-03-13 01:54:39'),
(84, 7, 'SB-22/PT คือ?', 'SB-22/PT คือชุดสายเชื่อมต่อโทรศัพท์สนาม', '2025-03-13 01:54:39', '2025-03-13 01:54:39'),
(85, 7, 'การบำรุงรักษาสายสื่อสารประเภทสาย ควรทำอย่างไร?', 'การตรวจสอบสภาพสายสม่ำเสมอช่วยป้องกันปัญหาและยืดอายุการใช้งานของสาย', '2025-03-13 01:54:39', '2025-03-13 01:54:39'),
(86, 7, 'สายสื่อสารแบบใดที่เหมาะสมที่สุดสำหรับการสื่อสารทางไกลในสภาพภูมิประเทศที่เป็นภูเขา?', 'ใยแก้วนำแสงมีความสามารถในการส่งสัญญาณได้ไกลและมีการสูญเสียสัญญาณน้อย จึงเหมาะสมกับสภาพภูมิประเทศที่เป็นอุปสรรค', '2025-03-13 01:54:39', '2025-03-13 01:54:39'),
(87, 7, 'ข้อใดคือข้อดีของการใช้สายคู่บิดเกลียว?', 'สายคู่บิดเกลียวมีราคาถูกและติดตั้งง่าย จึงนิยมใช้ในระบบโทรศัพท์', '2025-03-13 01:54:39', '2025-03-13 01:54:39'),
(88, 7, 'สายโคแอกเชียลใช้ในการสื่อสารประเภทใด?', 'สายโคแอกเชียลเหมาะสำหรับการส่งสัญญาณภาพและเสียงที่มีความถี่สูง เช่น โทรทัศน์และอินเทอร์เน็ตความเร็วสูง', '2025-03-13 01:54:39', '2025-03-13 01:54:39'),
(89, 7, 'การต่อสายสื่อสารแบบใดที่ต้องใช้หัวต่อชนิด ST, SC, LC?', 'หัวต่อ ST, SC, LC เป็นหัวต่อที่ใช้กับใยแก้วนำแสง', '2025-03-13 01:54:39', '2025-03-13 01:54:39'),
(90, 7, 'ข้อเสียของการใช้สายสื่อสารแบบไร้สายคือ?', 'สัญญาณไร้สายอาจถูกรบกวนจากสภาพอากาศหรือสัญญาณอื่นๆ', '2025-03-13 01:54:39', '2025-03-13 01:54:39'),
(91, 7, 'หน่วยใดในกองทัพบกที่รับผิดชอบหลักด้านการสื่อสาร?', 'กรมการสื่อสารทหารบกเป็นหน่วยหลักที่รับผิดชอบด้านการสื่อสารในกองทัพบก', '2025-03-13 01:54:39', '2025-03-13 01:54:39'),
(92, 7, 'การเข้ารหัสสัญญาณสื่อสารมีจุดประสงค์หลักเพื่ออะไร?', 'การเข้ารหัสช่วยปกป้องข้อมูลจากการดักฟัง', '2025-03-13 01:54:39', '2025-03-13 01:54:39'),
(93, 7, 'เครื่องมือใดที่ใช้ในการตรวจสอบสัญญาณสายสื่อสาร?', 'เครื่องทดสอบสายสื่อสารใช้ตรวจสอบคุณภาพและความสมบูรณ์ของสายสื่อสาร', '2025-03-13 01:54:39', '2025-03-13 01:54:39'),
(94, 7, 'ในการวางสายสื่อสารภาคสนาม ควรคำนึงถึงปัจจัยใดเป็นสำคัญ?', 'ความปลอดภัยของเส้นทางสายสื่อสารเป็นสิ่งสำคัญเพื่อป้องกันการถูกทำลายหรือตัดขาด', '2025-03-13 01:54:39', '2025-03-13 01:54:39'),
(95, 7, 'คำว่า “SEMI-RIGID”  หมายถึงสายสื่อสารประเภทใด?', 'SEMI-RIGID คือสายโคแอกเชียลแบบกึ่งแข็ง', '2025-03-13 01:54:39', '2025-03-13 01:54:39'),
(96, 8, 'ข้อใดต่อไปนี้เป็นความถี่ที่กองทัพบกไทยนิยมใช้ในการสื่อสารทางวิทยุ?', 'กองทัพบกไทยนิยมใช้ความถี่ VHF และ UHF ในการสื่อสารทางวิทยุ  แต่ VHF เป็นความถี่ที่นิยมใช้มากกว่า เนื่องจากมีคุณสมบัติเหมาะสมกับการใช้งานในพื้นที่ที่มีลักษณะภูมิประเทศหลากหลายของประเทศไทย', '2025-03-13 03:37:27', '2025-03-13 03:37:27'),
(97, 8, 'เครื่องมือสื่อสารทางทหารแบบใดที่ใช้ในการสื่อสารทางไกล?', 'วิทยุสื่อสารแบบตั้งฐานมีกำลังส่งสูงและเสาอากาศขนาดใหญ่ จึงสามารถสื่อสารได้ในระยะไกลกว่าเครื่องมือสื่อสารแบบอื่นๆ', '2025-03-13 03:37:27', '2025-03-13 03:37:27'),
(98, 8, 'การเข้ารหัสสัญญาณวิทยุมีความสำคัญอย่างไรในการสื่อสารทางทหาร?', 'การเข้ารหัสสัญญาณวิทยุช่วยให้ข้อมูลที่ส่งผ่านทางวิทยุถูกเก็บเป็นความลับ ป้องกันไม่ให้ฝ่ายตรงข้ามสามารถเข้าใจข้อมูลได้', '2025-03-13 03:37:27', '2025-03-13 03:37:27'),
(99, 8, 'คำว่า \"SITREP\" ในการสื่อสารทางทหารหมายถึงอะไร?', 'SITREP ย่อมาจาก Situation Report หมายถึง รายงานสถานการณ์', '2025-03-13 03:37:27', '2025-03-13 03:37:27'),
(100, 8, 'ในการสื่อสารทางวิทยุทางทหาร โรงเรียนทหารสื่อสารมีบทบาทสำคัญอย่างไร?', 'โรงเรียนทหารสื่อสารมีหน้าที่หลักในการฝึกอบรมบุคลากรให้มีความรู้ความสามารถในการใช้งานและบำรุงรักษาเครื่องมือสื่อสารทางทหาร รวมถึงการวางแผนและดำเนินการสื่อสารทางทหารอย่างมีประสิทธิภาพ', '2025-03-13 03:37:27', '2025-03-13 03:37:27'),
(101, 8, 'ระบบวิทยุสื่อสารทางยุทธวิธีแบบใดที่ใช้ความถี่กระโดด (Frequency Hopping) เพื่อป้องกันการดักฟัง?', 'SINCGARS (Single Channel Ground and Airborne Radio System) เป็นระบบวิทยุสื่อสารทางยุทธวิธีที่ใช้ความถี่กระโดดเพื่อเพิ่มความปลอดภัยในการสื่อสาร', '2025-03-13 03:37:27', '2025-03-13 03:37:27'),
(102, 8, 'ข้อใดต่อไปนี้เป็นความถี่ที่ใช้ในการสื่อสารทางทหารในย่าน HF?', 'ย่านความถี่ HF (High Frequency) สำหรับการสื่อสารทางทหารอยู่ในช่วง 3-30 MHz', '2025-03-13 03:37:27', '2025-03-13 03:37:27'),
(103, 8, 'การสื่อสารแบบใดที่เหมาะสมที่สุดสำหรับการส่งข้อมูลในระยะไกลโดยไม่มีสิ่งกีดขวาง?', 'Skywave propagation ใช้การสะท้อนคลื่นวิทยุจากชั้นบรรยากาศไอโอโนสเฟียร์ ทำให้สามารถสื่อสารในระยะไกลได้', '2025-03-13 03:37:27', '2025-03-13 03:37:27'),
(104, 8, 'อะไรคือข้อจำกัดหลักของการสื่อสารด้วยวิทยุ VHF/UHF?', 'VHF/UHF signals propagate primarily by line-of-sight, limiting their range.', '2025-03-13 03:37:27', '2025-03-13 03:37:27'),
(105, 8, 'หน้าที่หลักของเครื่อง AN/PRC-148 คืออะไร?', 'AN/PRC-148 เป็นวิทยุสื่อสารทางทหาร', '2025-03-13 03:37:27', '2025-03-13 03:37:27'),
(106, 8, 'คำย่อ “COMSEC” หมายถึงอะไร?', 'COMSEC ย่อมาจาก Communications Security', '2025-03-13 03:37:27', '2025-03-13 03:37:27'),
(107, 8, 'การใช้รหัสในการสื่อสารทางวิทยุมีจุดประสงค์หลักเพื่ออะไร?', 'การใช้รหัสช่วยป้องกันการดักฟังและถอดรหัสข้อมูลโดยฝ่ายตรงข้าม', '2025-03-13 03:37:27', '2025-03-13 03:37:27'),
(108, 8, 'สัญญาณรบกวนแบบใดที่เกิดจากสภาพอากาศ?', 'Atmospheric noise เกิดจากปรากฏการณ์ทางธรรมชาติ เช่น ฟ้าผ่า', '2025-03-13 03:37:27', '2025-03-13 03:37:27'),
(109, 8, 'การปรับคลื่นแบบใดที่ใช้ในการส่งข้อมูลดิจิทัล?', 'FSK (Frequency Shift Keying) เป็นการปรับคลื่นแบบดิจิทัล', '2025-03-13 03:37:27', '2025-03-13 03:37:27'),
(110, 8, 'อะไรคือความสำคัญของ SOP ในการสื่อสารทางทหาร?', 'SOP (Standard Operating Procedure) ช่วยให้การสื่อสารเป็นไปอย่างมีระเบียบและเข้าใจตรงกัน', '2025-03-13 03:37:27', '2025-03-13 03:37:27'),
(136, 12, 'คำใดเป็นคำที่มีตัวสะกด?', 'คำว่า \"กา\" มีตัวสะกด คือ ก ไก่ และสระอา', '2025-03-15 17:08:59', '2025-03-15 17:08:59'),
(137, 12, 'ข้อใดเป็นสระทั้งหมด', 'อะ อา อิ เป็นสระในภาษาไทย', '2025-03-15 17:08:59', '2025-03-15 17:08:59'),
(138, 12, 'คำว่า \"โรงเรียน\" มีกี่พยางค์?', 'คำว่า \"โรงเรียน\" แบ่งเป็น \"โรง\" และ \"เรียน\" รวมเป็นสองพยางค์', '2025-03-15 17:08:59', '2025-03-15 17:08:59'),
(139, 12, 'ข้อใดเป็นคำที่มีความหมายตรงข้ามกับคำว่า \"ใหญ่\"', '\"เล็ก\" มีความหมายตรงข้ามกับ \"ใหญ่\"', '2025-03-15 17:08:59', '2025-03-15 17:08:59'),
(140, 12, 'คำว่า \"สวย\" มีความหมายใกล้เคียงกับคำใด', '\"งาม\" มีความหมายใกล้เคียงกับ \"สวย\"', '2025-03-15 17:08:59', '2025-03-15 17:08:59'),
(141, 12, 'ข้อใดคือวรรณยุกต์เอก', '่ คือสัญลักษณ์ของวรรณยุกต์เอก', '2025-03-15 17:08:59', '2025-03-15 17:08:59'),
(142, 12, 'คำว่า \"แม่\" ประสมด้วยสระอะไร', 'คำว่า \"แม่\" ประสมด้วยสระแอ', '2025-03-15 17:08:59', '2025-03-15 17:08:59'),
(143, 12, 'พยัญชนะตัวใดเป็นอักษรต่ำ', 'ง งู เป็นอักษรต่ำ', '2025-03-15 17:08:59', '2025-03-15 17:08:59'),
(144, 12, 'คำใดสะกดด้วย \"น\"', 'คำว่า \"กิน\" สะกดด้วย น หนู', '2025-03-15 17:08:59', '2025-03-15 17:08:59'),
(145, 12, 'คำว่า \"เด็ก\" มีตัวอะไรเป็นตัวสะกด', 'คำว่า \"เด็ก\" มี ก ไก่ เป็นตัวสะกด', '2025-03-15 17:08:59', '2025-03-15 17:08:59'),
(156, 14, 'What is the primary purpose of an instruction set architecture (ISA)?', 'The ISA defines the programmer-visible aspects of the processor, including the instruction set, registers, and memory addressing modes, providing a standard interface for software.', '2025-03-16 03:42:22', '2025-03-16 03:42:22'),
(157, 14, 'Which of the following best describes the concept of pipelining in computer architecture?', 'Pipelining improves performance by overlapping the execution stages of different instructions, increasing instruction throughput.', '2025-03-16 03:42:22', '2025-03-16 03:42:22'),
(158, 14, 'What is the role of the Memory Management Unit (MMU) in a computer system?', 'The MMU is responsible for virtual memory management, translating virtual addresses used by programs into physical addresses in RAM, and enforcing memory protection to prevent processes from interfering with each other.', '2025-03-16 03:42:22', '2025-03-16 03:42:22'),
(159, 14, 'Which addressing mode involves adding a constant value to the contents of a register to obtain the memory address?', 'Indexed addressing adds a constant offset to the value in a register to calculate the effective memory address. This is useful for accessing elements in arrays.', '2025-03-16 03:42:22', '2025-03-16 03:42:22'),
(160, 14, 'What is the purpose of cache coherence protocols in multiprocessor systems?', 'Cache coherence protocols maintain consistency of data stored in multiple caches in a shared memory multiprocessor system, ensuring that all processors see the most up-to-date data.', '2025-03-16 03:42:22', '2025-03-16 03:42:22'),
(161, 14, 'Which of the following is a characteristic of RISC (Reduced Instruction Set Computing) architectures?', 'RISC architectures are characterized by simple, fixed-length instructions, a large register file, and a load/store architecture, aiming for faster instruction execution.', '2025-03-16 03:42:22', '2025-03-16 03:42:22'),
(162, 14, 'What is the main advantage of using DMA (Direct Memory Access)?', 'DMA enables peripheral devices to transfer data to or from memory independently of the CPU, freeing up the CPU to perform other tasks and improving system performance.', '2025-03-16 03:42:22', '2025-03-16 03:42:22'),
(163, 14, 'Which level of RAID provides the best fault tolerance with minimum space overhead?', 'RAID 5 uses striping with parity, providing good fault tolerance with a space overhead of only one drive\'s capacity, regardless of the number of drives in the array.', '2025-03-16 03:42:22', '2025-03-16 03:42:22'),
(164, 14, 'What is the primary function of a compiler?', 'A compiler translates source code written in a high-level language (e.g., C++, Java) into a lower-level language (e.g., assembly or machine code) that can be executed by the computer.', '2025-03-16 03:42:22', '2025-03-16 03:42:22'),
(165, 14, 'In the context of computer security, what does \'least privilege\' principle refer to?', 'The principle of least privilege dictates that users should be granted only the minimum level of access necessary to perform their duties. This minimizes the potential damage from security breaches or malicious activities.', '2025-03-16 03:42:22', '2025-03-16 03:42:22'),
(166, 15, 'ข้อใดคือปัจจัยสำคัญที่สุดที่ส่งผลต่อการเปลี่ยนแปลงทางสังคม?', 'เทคโนโลยีมีบทบาทสำคัญในการเปลี่ยนแปลงวิถีชีวิต, การสื่อสาร, และเศรษฐกิจ ซึ่งส่งผลกระทบต่อสังคมในวงกว้าง', '2025-03-16 04:41:37', '2025-03-16 04:41:37'),
(167, 15, 'สนธิสัญญาใดที่ยุติสงครามโลกครั้งที่หนึ่ง?', 'สนธิสัญญาแวร์ซายเป็นสนธิสัญญาที่ลงนามโดยฝ่ายสัมพันธมิตรและเยอรมนีเพื่อยุติสงครามโลกครั้งที่หนึ่ง', '2025-03-16 04:41:37', '2025-03-16 04:41:37'),
(168, 15, 'ข้อใดคือหน้าที่หลักของรัฐบาล?', 'รัฐบาลมีหน้าที่หลักในการปกป้องประเทศ, รักษาความสงบ, และบังคับใช้กฎหมาย', '2025-03-16 04:41:37', '2025-03-16 04:41:37'),
(169, 15, 'องค์กรใดมีหน้าที่หลักในการรักษาสันติภาพและความมั่นคงระหว่างประเทศ?', 'องค์การสหประชาชาติ (UN) ก่อตั้งขึ้นเพื่อรักษาสันติภาพและความมั่นคงระหว่างประเทศ, ส่งเสริมความร่วมมือระหว่างประเทศ, และแก้ไขปัญหาระหว่างประเทศ', '2025-03-16 04:41:37', '2025-03-16 04:41:37'),
(170, 15, 'ข้อใดคือความหมายของคำว่า \'ประชาธิปไตย\'?', 'ประชาธิปไตยเป็นระบอบการปกครองที่อำนาจอธิปไตยเป็นของประชาชน', '2025-03-16 04:41:37', '2025-03-16 04:41:37'),
(171, 15, 'เศรษฐกิจพอเพียงตามแนวพระราชดำริของในหลวงรัชกาลที่ 9 เน้นเรื่องใด?', 'เศรษฐกิจพอเพียงเน้นการพึ่งพาตนเอง, ความพอประมาณ, ความมีเหตุผล, และการมีภูมิคุ้มกันในตัวที่ดี', '2025-03-16 04:41:37', '2025-03-16 04:41:37'),
(172, 15, 'ข้อใดคือผลกระทบเชิงลบที่สำคัญที่สุดของการโลกาภิวัตน์?', 'การโลกาภิวัตน์อาจนำไปสู่การลดลงของความหลากหลายทางวัฒนธรรมเนื่องจากการแพร่หลายของวัฒนธรรมกระแสหลัก', '2025-03-16 04:41:37', '2025-03-16 04:41:37'),
(173, 15, 'ข้อใดคือสาเหตุหลักของการเกิดภาวะโลกร้อน?', 'การปล่อยก๊าซเรือนกระจกจากกิจกรรมของมนุษย์ เช่น การเผาไหม้เชื้อเพลิงฟอสซิล เป็นสาเหตุหลักของการเกิดภาวะโลกร้อน', '2025-03-16 04:41:37', '2025-03-16 04:41:37'),
(174, 15, 'ข้อใดคือความหมายของ \'ธรรมาภิบาล\'?', 'ธรรมาภิบาลหมายถึงการบริหารจัดการองค์กรหรือประเทศด้วยหลักความโปร่งใส, ความรับผิดชอบ, ความเป็นธรรม, และการมีส่วนร่วม', '2025-03-16 04:41:37', '2025-03-16 04:41:37'),
(175, 15, 'ข้อใดคือลักษณะสำคัญของสังคมไทยในปัจจุบัน?', 'ปัจจุบันประเทศไทยเป็นสังคมอุตสาหกรรมที่เน้นการผลิตและการส่งออกสินค้าไปยังต่างประเทศ', '2025-03-16 04:41:37', '2025-03-16 04:41:37'),
(206, 19, 'วัตถุประสงค์หลักของการทำลายวัตถุระเบิดคืออะไร?', 'วัตถุประสงค์หลักคือการกำจัดอันตรายที่เกิดจากวัตถุระเบิด เพื่อความปลอดภัยของบุคคลและพื้นที่', '2025-03-18 07:05:39', '2025-03-18 07:05:39'),
(207, 19, 'วิธีการทำลายวัตถุระเบิดวิธีใดที่ถือว่าปลอดภัยที่สุด?', 'การทำลายด้วยการระเบิดควบคุม เป็นวิธีที่ปลอดภัยที่สุด เนื่องจากสามารถควบคุมทิศทางและความรุนแรงของการระเบิดได้', '2025-03-18 07:05:39', '2025-03-18 07:05:39'),
(208, 19, 'ก่อนทำการทำลายวัตถุระเบิด สิ่งแรกที่ต้องทำคืออะไร?', 'การประเมินสถานการณ์และภัยคุกคามเป็นสิ่งแรกที่ต้องทำ เพื่อวางแผนการทำลายที่เหมาะสมและปลอดภัยที่สุด', '2025-03-18 07:05:39', '2025-03-18 07:05:39'),
(209, 19, 'อุปกรณ์ใดที่ใช้ในการทำลายวัตถุระเบิดโดยการตัดวงจรไฟฟ้า?', 'เครื่องมือตัดวงจร (Disruptor) ออกแบบมาเพื่อทำลายหรือตัดวงจรไฟฟ้าของวัตถุระเบิดโดยเฉพาะ', '2025-03-18 07:05:39', '2025-03-18 07:05:39'),
(210, 19, 'ข้อใดคืออันตรายที่อาจเกิดขึ้นระหว่างการทำลายวัตถุระเบิด?', 'การระเบิดก่อนกำหนดเป็นอันตรายร้ายแรงที่สุดที่อาจเกิดขึ้นระหว่างการทำลายวัตถุระเบิด', '2025-03-18 07:05:39', '2025-03-18 07:05:39'),
(211, 19, 'หลักการ \'Safety Distance\' มีความสำคัญอย่างไรในการทำลายวัตถุระเบิด?', 'Safety Distance คือระยะห่างที่ปลอดภัยจากจุดระเบิด เพื่อลดความเสี่ยงจากแรงระเบิดและสะเก็ดระเบิด', '2025-03-18 07:05:39', '2025-03-18 07:05:39'),
(212, 19, 'ข้อใดคือขั้นตอนสุดท้ายหลังจากการทำลายวัตถุระเบิดเสร็จสิ้น?', 'การตรวจสอบพื้นที่หลังการทำลาย เพื่อยืนยันว่าไม่มีวัตถุระเบิดหลงเหลืออยู่ และพื้นที่ปลอดภัย', '2025-03-18 07:05:39', '2025-03-18 07:05:39'),
(213, 19, 'การใช้ \'น้ำ\' ในการทำลายวัตถุระเบิดมีประโยชน์อย่างไร?', 'น้ำช่วยลดแรงดันจากการระเบิด ทำให้การระเบิดเป็นไปอย่างควบคุมมากขึ้น และลดความรุนแรงโดยรวม', '2025-03-18 07:05:39', '2025-03-18 07:05:39'),
(214, 19, 'วัตถุระเบิดชนิดใดที่ต้องระมัดระวังเป็นพิเศษเนื่องจากมีความไวต่อแรงสั่นสะเทือน?', 'ระเบิดแสวงเครื่อง (IED) มักมีกลไกที่ซับซ้อนและอาจไวต่อแรงสั่นสะเทือน ทำให้ต้องระมัดระวังเป็นพิเศษ', '2025-03-18 07:05:39', '2025-03-18 07:05:39'),
(215, 19, 'ข้อใดคือคุณสมบัติที่สำคัญที่สุดของเจ้าหน้าที่ทำลายวัตถุระเบิด?', 'ความใจเย็นและรอบคอบเป็นคุณสมบัติที่สำคัญที่สุด เนื่องจากต้องตัดสินใจอย่างถูกต้องภายใต้ความกดดันสูง และต้องปฏิบัติตามขั้นตอนอย่างเคร่งครัด', '2025-03-18 07:05:39', '2025-03-18 07:05:39'),
(346, 28, 'ข้อใดคือสมการบัญชีขั้นพื้นฐาน?', 'สมการบัญชีขั้นพื้นฐานคือ สินทรัพย์ = หนี้สิน + ส่วนของเจ้าของ ซึ่งแสดงความสัมพันธ์ระหว่างสิ่งที่กิจการเป็นเจ้าของ (สินทรัพย์) กับแหล่งที่มาของเงินทุน (หนี้สินและส่วนของเจ้าของ)', '2025-03-20 06:53:54', '2025-03-20 06:53:54'),
(347, 28, 'ข้อใดคือบัญชีหมวดสินทรัพย์?', 'เงินสดเป็นสินทรัพย์หมุนเวียน เจ้าหนี้การค้าเป็นหนี้สิน ทุนเป็นส่วนของเจ้าของ และค่าใช้จ่ายเป็นส่วนหนึ่งของการคำนวณกำไรสุทธิ', '2025-03-20 06:53:54', '2025-03-20 06:53:54'),
(348, 28, 'ข้อใดคือบัญชีหมวดหนี้สิน?', 'เงินกู้ยืมระยะยาวเป็นภาระผูกพันที่กิจการต้องชำระคืนในอนาคต ลูกหนี้การค้าเป็นสินทรัพย์ อาคารเป็นสินทรัพย์ และรายได้เป็นส่วนหนึ่งของการคำนวณกำไรสุทธิ', '2025-03-20 06:53:54', '2025-03-20 06:53:54'),
(349, 28, 'ข้อใดคือบัญชีหมวดส่วนของเจ้าของ?', 'กำไรสะสมคือส่วนหนึ่งของส่วนของเจ้าของที่แสดงถึงกำไรที่กิจการเก็บสะสมไว้ ค่าเสื่อมราคาเป็นค่าใช้จ่าย สินค้าคงเหลือเป็นสินทรัพย์ และค่าเช่าเป็นค่าใช้จ่าย', '2025-03-20 06:53:54', '2025-03-20 06:53:54'),
(350, 28, 'การบันทึกบัญชีตามหลักการบัญชีคู่ (Double-entry bookkeeping) หมายถึงอะไร?', 'หลักการบัญชีคู่กำหนดให้ทุกรายการค้าต้องบันทึกทั้งด้านเดบิตและเครดิต โดยผลรวมของเดบิตต้องเท่ากับผลรวมของเครดิตเสมอ', '2025-03-20 06:53:54', '2025-03-20 06:53:54'),
(351, 28, 'ข้อใดคือความหมายของ \"เดบิต\" (Debit)?', '\"เดบิต\" หมายถึงด้านซ้ายของบัญชี', '2025-03-20 06:53:54', '2025-03-20 06:53:54'),
(352, 28, 'ข้อใดคือความหมายของ \"เครดิต\" (Credit)?', '\"เครดิต\" หมายถึงด้านขวาของบัญชี', '2025-03-20 06:53:54', '2025-03-20 06:53:54'),
(353, 28, 'งบการเงินใดที่แสดงฐานะทางการเงินของกิจการ ณ วันใดวันหนึ่ง?', 'งบแสดงฐานะการเงิน (Balance Sheet) แสดงสินทรัพย์ หนี้สิน และส่วนของเจ้าของ ณ วันใดวันหนึ่ง', '2025-03-20 06:53:54', '2025-03-20 06:53:54'),
(354, 28, 'งบการเงินใดที่แสดงผลการดำเนินงานของกิจการในช่วงระยะเวลาหนึ่ง?', 'งบกำไรขาดทุน (Income Statement) แสดงรายได้ ค่าใช้จ่าย และกำไร (ขาดทุน) สุทธิ ในช่วงระยะเวลาหนึ่ง', '2025-03-20 06:53:54', '2025-03-20 06:53:54'),
(355, 28, 'ข้อใดคือประโยชน์ของการทำบัญชี?', 'ข้อมูลทางบัญชีช่วยให้ผู้บริหารและผู้ที่เกี่ยวข้องสามารถตัดสินใจทางธุรกิจได้อย่างมีประสิทธิภาพ เช่น การวางแผน การควบคุม และการประเมินผล', '2025-03-20 06:53:54', '2025-03-20 06:53:54'),
(356, 28, 'ข้อใดคือสมการบัญชีขั้นพื้นฐาน?', 'สมการบัญชีขั้นพื้นฐานคือ สินทรัพย์ = หนี้สิน + ส่วนของผู้ถือหุ้น ซึ่งแสดงความสัมพันธ์ระหว่างสิ่งที่กิจการเป็นเจ้าของ หนี้สินที่กิจการมี และส่วนได้เสียของผู้ถือหุ้น', '2025-03-20 06:53:54', '2025-03-20 06:53:54'),
(357, 28, 'รายการใดต่อไปนี้ถือเป็น \'สินทรัพย์หมุนเวียน\'?', 'เงินสดถือเป็นสินทรัพย์หมุนเวียน เนื่องจากสามารถเปลี่ยนเป็นเงินสดหรือใช้ภายในระยะเวลาหนึ่งปี หรือรอบระยะเวลาการดำเนินงานตามปกติ', '2025-03-20 06:53:54', '2025-03-20 06:53:54'),
(358, 28, 'ข้อใดคือวัตถุประสงค์หลักของงบกระแสเงินสด?', 'งบกระแสเงินสดมีวัตถุประสงค์หลักเพื่อแสดงการเปลี่ยนแปลงของเงินสดและรายการเทียบเท่าเงินสดของกิจการในช่วงเวลาหนึ่ง', '2025-03-20 06:53:54', '2025-03-20 06:53:54'),
(359, 28, 'การบันทึกรายการ \'เดบิต\' หมายถึงอะไร?', 'โดยทั่วไป การบันทึกรายการ \'เดบิต\' หมายถึงการเพิ่มขึ้นของสินทรัพย์หรือค่าใช้จ่าย หรือการลดลงของหนี้สินหรือส่วนของผู้ถือหุ้น', '2025-03-20 06:53:54', '2025-03-20 06:53:54'),
(360, 28, 'ข้อใดคือความหมายของ \'ค่าเสื่อมราคา\'?', 'ค่าเสื่อมราคาคือการปันส่วนต้นทุนของสินทรัพย์ถาวรตลอดอายุการใช้งานอย่างเป็นระบบ', '2025-03-20 06:53:54', '2025-03-20 06:53:54'),
(361, 28, 'มาตรฐานการรายงานทางการเงิน (TFRS) มีไว้เพื่ออะไร?', 'มาตรฐานการรายงานทางการเงิน (TFRS) มีไว้เพื่อให้ข้อมูลทางการเงินมีความน่าเชื่อถือและสามารถเปรียบเทียบได้ระหว่างกิจการต่างๆ', '2025-03-20 06:53:54', '2025-03-20 06:53:54'),
(362, 28, 'ข้อใดคือลักษณะสำคัญของ \'หลักการจับคู่\' (Matching Principle)?', 'หลักการจับคู่ (Matching Principle) คือการจับคู่รายได้และค่าใช้จ่ายที่เกี่ยวข้องในงวดบัญชีเดียวกัน เพื่อให้แสดงผลการดำเนินงานที่ถูกต้อง', '2025-03-20 06:53:54', '2025-03-20 06:53:54'),
(363, 28, 'ข้อใดเป็นรายการที่แสดงในงบกำไรขาดทุนเบ็ดเสร็จ?', 'รายได้จากการขายเป็นรายการที่แสดงในงบกำไรขาดทุนเบ็ดเสร็จ เพื่อแสดงผลการดำเนินงานของกิจการ', '2025-03-20 06:53:54', '2025-03-20 06:53:54'),
(364, 28, 'การกระทบยอดเงินฝากธนาคาร (Bank Reconciliation) มีวัตถุประสงค์เพื่ออะไร?', 'การกระทบยอดเงินฝากธนาคาร (Bank Reconciliation) มีวัตถุประสงค์เพื่อตรวจสอบความถูกต้องของรายการระหว่างบัญชีของกิจการและบัญชีธนาคาร และหาสาเหตุของความแตกต่าง', '2025-03-20 06:53:54', '2025-03-20 06:53:54'),
(365, 28, 'ข้อใดคือความหมายของ \'สินค้าคงเหลือ\'?', 'สินค้าคงเหลือคือสินค้าที่กิจการมีไว้เพื่อขายตามปกติธุรกิจ หรืออยู่ในระหว่างการผลิตเพื่อขาย', '2025-03-20 06:53:54', '2025-03-20 06:53:54'),
(421, 32, 'ข้อใด *ไม่ใช่* องค์ประกอบพื้นฐานของสังคม?', 'เทคโนโลยีขั้นสูงเป็นสิ่งที่พัฒนาขึ้นภายหลัง ไม่ใช่องค์ประกอบพื้นฐานดั้งเดิมของสังคม องค์ประกอบพื้นฐานคือ ประชากร ดินแดน และอำนาจอธิปไตย (ในกรณีรัฐชาติ)', '2025-03-22 07:16:33', '2025-03-22 07:16:33'),
(422, 32, 'สถาบันทางสังคมใดที่ทำหน้าที่อบรมสั่งสอนสมาชิกใหม่ของสังคมเป็นหลัก?', 'สถาบันครอบครัวเป็นสถาบันแรกที่บุคคลมีปฏิสัมพันธ์ด้วย และทำหน้าที่หลักในการถ่ายทอดวัฒนธรรม ค่านิยม และบรรทัดฐานทางสังคม', '2025-03-22 07:16:33', '2025-03-22 07:16:33'),
(423, 32, 'ข้อใดคือความหมายของ \"บรรทัดฐานทางสังคม\"?', 'บรรทัดฐานทางสังคมคือแนวทางปฏิบัติที่สังคมคาดหวังและยอมรับ ซึ่งอาจเป็นได้ทั้งกฎหมายที่เป็นทางการและกฎเกณฑ์ที่ไม่เป็นทางการ', '2025-03-22 07:16:33', '2025-03-22 07:16:33'),
(424, 32, 'ข้อใด *ไม่ใช่* หน้าที่ของสถาบันการศึกษา?', 'การสร้างความเสมอภาคทางเศรษฐกิจเป็นหน้าที่หลักของสถาบันเศรษฐกิจและสถาบันการเมืองมากกว่า แม้สถาบันการศึกษาจะมีส่วนช่วยลดความเหลื่อมล้ำได้บ้าง แต่ไม่ใช่หน้าที่หลัก', '2025-03-22 07:16:33', '2025-03-22 07:16:33'),
(425, 32, 'ข้อใดคือความหมายของ \"วัฒนธรรม\"?', 'วัฒนธรรมครอบคลุมทุกแง่มุมของวิถีชีวิตของกลุ่มคน รวมถึงความเชื่อ ค่านิยม ภาษา ศิลปะ และประเพณี', '2025-03-22 07:16:33', '2025-03-22 07:16:33'),
(426, 32, 'การกระทำใดเป็นการ \"จัดระเบียบทางสังคม\"?', 'การปฏิบัติตามกฎจราจรเป็นการทำตามกฎเกณฑ์ที่สังคมกำหนด เพื่อให้เกิดความเป็นระเบียบเรียบร้อย', '2025-03-22 07:16:33', '2025-03-22 07:16:33'),
(427, 32, 'ข้อใดคือความหมายของ \"สถานภาพ\" (Status) ทางสังคม?', 'สถานภาพคือตำแหน่งที่บุคคลดำรงอยู่ในสังคม ซึ่งอาจได้มาตั้งแต่กำเนิด (ascribed status) หรือได้มาภายหลัง (achieved status)', '2025-03-22 07:16:33', '2025-03-22 07:16:33'),
(428, 32, 'ข้อใดคือความหมายของ \"บทบาท\" (Role) ทางสังคม?', 'บทบาทคือพฤติกรรมที่สังคมคาดหวังให้บุคคลแสดงออกตามสถานภาพที่เขาดำรงอยู่ เช่น บทบาทของครูคือการสอนหนังสือ', '2025-03-22 07:16:33', '2025-03-22 07:16:33'),
(429, 32, 'ข้อใด *ไม่ใช่* ลักษณะของสังคม?', 'สังคมประกอบด้วยบุคคลที่มีความหลากหลาย มีความคิดเห็น ความเชื่อ และค่านิยมที่แตกต่างกัน ไม่จำเป็นต้องเหมือนกันทั้งหมด', '2025-03-22 07:16:33', '2025-03-22 07:16:33'),
(430, 32, 'สถาบันทางสังคมใดมีหน้าที่หลักในการผลิตและแจกจ่ายสินค้าและบริการ?', 'สถาบันเศรษฐกิจมีหน้าที่เกี่ยวข้องกับการผลิต การจัดจำหน่าย และการบริโภคสินค้าและบริการ เพื่อตอบสนองความต้องการของสมาชิกในสังคม', '2025-03-22 07:16:33', '2025-03-22 07:16:33'),
(431, 32, 'ข้อใด *ไม่ใช่* องค์ประกอบสำคัญของโครงสร้างทางสังคม?', 'ความเชื่อส่วนบุคคลเป็นเรื่องของปัจเจกบุคคล ไม่ใช่องค์ประกอบหลักที่กำหนดโครงสร้างของสังคมโดยรวม ซึ่งเน้นที่สถาบัน กลุ่ม สถานภาพ และบทบาท', '2025-03-22 07:16:33', '2025-03-22 07:16:33'),
(432, 32, 'ข้อใดแสดงถึงความสัมพันธ์ระหว่างสถานภาพ (Status) และบทบาท (Role) ได้ถูกต้องที่สุด?', 'สถานภาพคือตำแหน่งที่บุคคลนั้นๆ ดำรงอยู่ ส่วนบทบาทคือสิ่งที่สังคมคาดหวังให้บุคคลนั้นๆ ปฏิบัติตามสถานภาพของตน', '2025-03-22 07:16:33', '2025-03-22 07:16:33'),
(433, 32, 'การจัดระเบียบทางสังคม (Social Organization) มีจุดมุ่งหมายหลักเพื่ออะไร?', 'การจัดระเบียบทางสังคมมีเป้าหมายหลักคือการสร้างความเป็นระเบียบ เพื่อให้สังคมสามารถดำเนินไปได้อย่างปกติสุข', '2025-03-22 07:16:33', '2025-03-22 07:16:33'),
(434, 32, 'ข้อใด *ไม่ใช่* หน้าที่หลักของสถาบันครอบครัว?', 'การผลิตสินค้าและบริการเป็นหน้าที่หลักของสถาบันเศรษฐกิจ ไม่ใช่สถาบันครอบครัว', '2025-03-22 07:16:33', '2025-03-22 07:16:33'),
(435, 32, 'สถาบันใดมีบทบาทหลักในการแก้ไขข้อขัดแย้งและรักษาความยุติธรรมในสังคม?', 'สถาบันการเมืองการปกครอง โดยเฉพาะอย่างยิ่งระบบกฎหมายและศาล มีหน้าที่หลักในการตัดสินข้อพิพาทและรักษาความยุติธรรม', '2025-03-22 07:16:33', '2025-03-22 07:16:33'),
(436, 32, 'ข้อใดคือความหมายของ \"บรรทัดฐานทางสังคม\" (Social Norms) ที่ถูกต้องที่สุด?', 'บรรทัดฐานทางสังคมคือสิ่งที่สังคมคาดหวังให้สมาชิกปฏิบัติตาม เป็นแนวทางปฏิบัติที่ยอมรับกันโดยทั่วไป ไม่จำเป็นต้องเป็นกฎหมาย', '2025-03-22 07:16:33', '2025-03-22 07:16:33'),
(437, 32, 'การขัดเกลาทางสังคม (Socialization) หมายถึงกระบวนการใด?', 'การขัดเกลาทางสังคมคือกระบวนการที่บุคคลเรียนรู้ที่จะเป็นส่วนหนึ่งของสังคม ผ่านการซึมซับวัฒนธรรมและบรรทัดฐานต่างๆ', '2025-03-22 07:16:33', '2025-03-22 07:16:33'),
(438, 32, 'ข้อใด *ไม่ใช่* ลักษณะของกลุ่มปฐมภูมิ (Primary Group)?', 'กลุ่มปฐมภูมิมีความสัมพันธ์ใกล้ชิด ไม่เป็นทางการ ต่างจากกลุ่มทุติยภูมิที่มีความเป็นทางการและมีเป้าหมายชัดเจน', '2025-03-22 07:16:33', '2025-03-22 07:16:33'),
(439, 32, 'ข้อใดคือตัวอย่างของการเปลี่ยนแปลงทางสังคม (Social Change) ที่เกิดจากปัจจัยทางเทคโนโลยี?', 'การประดิษฐ์เครื่องจักรไอน้ำเป็นปัจจัยทางเทคโนโลยีที่นำไปสู่การเปลี่ยนแปลงครั้งใหญ่ในสังคม', '2025-03-22 07:16:33', '2025-03-22 07:16:33'),
(440, 32, 'วัฒนธรรมย่อย (Subculture) หมายถึงอะไร?', 'วัฒนธรรมย่อยคือวัฒนธรรมของกลุ่มคนที่มีลักษณะเฉพาะ แตกต่างจากวัฒนธรรมหลักของสังคม', '2025-03-22 07:16:33', '2025-03-22 07:16:33'),
(441, 32, 'ข้อใด *ไม่ใช่* องค์ประกอบสำคัญของโครงสร้างทางสังคม?', 'ความเชื่อส่วนบุคคลที่ไม่ส่งผลต่อสังคมโดยรวม ไม่ถือเป็นองค์ประกอบหลักของโครงสร้างสังคม ซึ่งเน้นที่ความสัมพันธ์และแบบแผนพฤติกรรมที่มีผลต่อคนหมู่มาก', '2025-03-22 07:16:33', '2025-03-22 07:16:33'),
(442, 32, 'การกระทำในข้อใดแสดงถึงการขัดเกลาทางสังคม (Socialization) ที่ *ไม่เหมาะสม*?', 'การสอนให้เชื่อฟังโดยไม่มีข้อโต้แย้ง ขัดกับหลักการขัดเกลาทางสังคมที่ควรส่งเสริมการคิดวิเคราะห์ และการตั้งคำถาม', '2025-03-22 07:16:33', '2025-03-22 07:16:33'),
(443, 32, 'ข้อใด *ไม่ใช่* หน้าที่หลักของสถาบันครอบครัว?', 'การกำหนดนโยบายเศรษฐกิจเป็นหน้าที่ของสถาบันการเมืองการปกครอง หรือสถาบันเศรษฐกิจ ไม่ใช่สถาบันครอบครัว', '2025-03-22 07:16:33', '2025-03-22 07:16:33'),
(444, 32, 'ข้อใดแสดงถึงความสัมพันธ์ระหว่างสถานภาพ (Status) และบทบาท (Role) ได้ถูกต้องที่สุด?', 'สถานภาพคือตำแหน่งหรือฐานะทางสังคม เช่น ครู นักเรียน พ่อ แม่ ส่วนบทบาทคือพฤติกรรมหรือหน้าที่ที่คาดหวังจากสถานภาพนั้น ๆ เช่น ครูมีบทบาทสอนหนังสือ', '2025-03-22 07:16:33', '2025-03-22 07:16:33'),
(445, 32, 'บรรทัดฐานทางสังคม (Social Norms) ประเภทใดที่มีบทลงโทษทางสังคมรุนแรงน้อยที่สุด?', 'วิถีชาวบ้าน (Folkways) เป็นบรรทัดฐานที่ไม่เป็นทางการและมีบทลงโทษทางสังคมไม่รุนแรง เช่น การถูกตำหนิ หรือการถูกมองด้วยสายตาไม่พอใจ', '2025-03-22 07:16:33', '2025-03-22 07:16:33'),
(446, 33, 'รูปสี่เหลี่ยมผืนผ้ามีด้านกว้าง 5 เซนติเมตร และด้านยาว 8 เซนติเมตร จะมีพื้นที่เท่าใด?', 'พื้นที่สี่เหลี่ยมผืนผ้า = กว้าง x ยาว = 5 x 8 = 40 ตารางเซนติเมตร', '2025-03-22 09:19:50', '2025-03-22 09:19:50'),
(447, 33, 'รูปสามเหลี่ยมมีฐานยาว 10 เซนติเมตร และสูง 6 เซนติเมตร จะมีพื้นที่เท่าใด?', 'พื้นที่สามเหลี่ยม = 1/2 x ฐาน x สูง = 1/2 x 10 x 6 = 30 ตารางเซนติเมตร', '2025-03-22 09:19:50', '2025-03-22 09:19:50'),
(448, 33, 'รูปวงกลมมีรัศมี 7 เซนติเมตร จะมีพื้นที่เท่าใด (กำหนด π ≈ 22/7)', 'พื้นที่วงกลม = πr² = (22/7) x 7 x 7 = 154 ตารางเซนติเมตร', '2025-03-22 09:19:50', '2025-03-22 09:19:50'),
(449, 33, 'รูปสี่เหลี่ยมจัตุรัสมีด้านยาวด้านละ 9 เซนติเมตร จะมีพื้นที่เท่าใด?', 'พื้นที่สี่เหลี่ยมจัตุรัส = ด้าน x ด้าน = 9 x 9 = 81 ตารางเซนติเมตร', '2025-03-22 09:19:50', '2025-03-22 09:19:50'),
(450, 33, 'รูปสี่เหลี่ยมคางหมูมีด้านคู่ขนานยาว 6 เซนติเมตร และ 8 เซนติเมตร และมีส่วนสูง 4 เซนติเมตร จะมีพื้นที่เท่าใด?', 'พื้นที่สี่เหลี่ยมคางหมู = 1/2 x ผลบวกด้านคู่ขนาน x สูง = 1/2 x (6+8) x 4 = 28 ตารางเซนติเมตร', '2025-03-22 09:19:50', '2025-03-22 09:19:50'),
(451, 33, 'รูปสี่เหลี่ยมด้านขนานมีฐานยาว 12 เซนติเมตร และสูง 5 เซนติเมตร จะมีพื้นที่เท่าใด?', 'พื้นที่สี่เหลี่ยมด้านขนาน = ฐาน x สูง = 12 x 5 = 60 ตารางเซนติเมตร', '2025-03-22 09:19:50', '2025-03-22 09:19:50'),
(452, 33, 'รูปหกเหลี่ยมด้านเท่า มีความยาวด้านละ 4 เซนติเมตร และมีเส้นตั้งฉากจากจุดศูนย์กลางไปยังด้าน (apothem) ยาวประมาณ 3.46 เซนติเมตร จะมีพื้นที่ประมาณเท่าใด?', 'พื้นที่หกเหลี่ยมด้านเท่า = (1/2) x เส้นรอบรูป x apothem = (1/2) x (6x4) x 3.46 ≈ 41.52 ตารางเซนติเมตร', '2025-03-22 09:19:50', '2025-03-22 09:19:50'),
(453, 33, 'ถ้าต้องการหาพื้นที่ของรูปว่าว ต้องทราบข้อมูลอะไรบ้าง', 'พื้นที่รูปว่าว = 1/2 x ผลคูณของเส้นทแยงมุม', '2025-03-22 09:19:50', '2025-03-22 09:19:50'),
(454, 33, 'ข้อใดคือสูตรการหาพื้นที่ของรูปสี่เหลี่ยมขนมเปียกปูน?', 'พื้นที่สี่เหลี่ยมขนมเปียกปูน = ฐาน x สูง หรือ 1/2 x ผลคูณของเส้นทแยงมุม (ทั้งสองสูตรใช้ได้)', '2025-03-22 09:19:50', '2025-03-22 09:19:50'),
(455, 33, 'วงกลมสองวงมีรัศมี 3 และ 5 เซนติเมตร ตามลำดับ พื้นที่ของวงกลมทั้งสองต่างกันเท่าใด (π ≈ 3.14)', 'พื้นที่วงกลมใหญ่ = π(5²) = 25π, พื้นที่วงกลมเล็ก = π(3²) = 9π, ผลต่าง = 25π - 9π = 16π ≈ 16 x 3.14 = 50.24 ตารางเซนติเมตร', '2025-03-22 09:19:50', '2025-03-22 09:19:50'),
(456, 34, 'ข้อใด *ไม่ใช่* ทัศนธาตุ?', 'อารมณ์เป็นสิ่งที่ศิลปินสื่อสารผ่านทัศนธาตุ ไม่ใช่ทัศนธาตุโดยตรง', '2025-03-22 09:22:27', '2025-03-22 09:22:27'),
(457, 34, 'ทัศนธาตุใดที่เกิดจากการเคลื่อนที่ของจุด?', 'เส้นเกิดจากการลากจุด หรือจุดที่เคลื่อนที่ต่อเนื่องกัน', '2025-03-22 09:22:27', '2025-03-22 09:22:27'),
(458, 34, 'ข้อใดคือความหมายของ \'รูปทรง\'?', 'รูปทรง (Form) มี 3 มิติ คือ กว้าง ยาว และหนา/ลึก ทำให้เห็นเป็นปริมาตร', '2025-03-22 09:22:27', '2025-03-22 09:22:27'),
(459, 34, 'ทัศนธาตุใดที่ช่วยสร้างความรู้สึกเคลื่อนไหวในงานศิลปะ?', 'เส้นลักษณะต่างๆ เช่น เส้นโค้ง เส้นเฉียง สามารถสร้างความรู้สึกเคลื่อนไหวได้', '2025-03-22 09:22:27', '2025-03-22 09:22:27'),
(460, 34, 'ข้อใด *ไม่ใช่* หน้าที่ของ \'บริเวณว่าง\' (Space) ในงานศิลปะ?', 'บริเวณว่าง (Space) ไม่ได้มีหน้าที่กำหนดสีหลัก สีหลักเป็นเรื่องของทัศนธาตุ \'สี\'', '2025-03-22 09:22:27', '2025-03-22 09:22:27'),
(461, 34, 'การใช้สีคู่ตรงข้ามกัน จะให้ความรู้สึกอย่างไร?', 'สีคู่ตรงข้าม (Complementary Colors) อยู่ตรงข้ามกันในวงจรสี ทำให้เกิดความขัดแย้งและโดดเด่น', '2025-03-22 09:22:27', '2025-03-22 09:22:27'),
(462, 34, 'ทัศนธาตุใดที่เกี่ยวข้องกับการรับรู้ทางสัมผัส?', 'พื้นผิว (Texture) สามารถรับรู้ได้ด้วยการสัมผัส (หรือการมองเห็นที่ให้ความรู้สึกเหมือนได้สัมผัส)', '2025-03-22 09:22:27', '2025-03-22 09:22:27'),
(463, 34, 'ข้อใดคือความหมายของ \'น้ำหนัก\' (Value) ในทัศนธาตุ?', 'น้ำหนัก (Value) หมายถึง ค่าความอ่อนแก่ของสี หรือความสว่าง-ความมืด (Light and Dark)', '2025-03-22 09:22:27', '2025-03-22 09:22:27'),
(464, 34, 'เส้นนอน ให้ความรู้สึกอย่างไร?', 'เส้นนอน ให้ความรู้สึกสงบ ราบเรียบ ผ่อนคลาย', '2025-03-22 09:22:27', '2025-03-22 09:22:27'),
(465, 34, 'การจัดวางองค์ประกอบภาพ โดยให้มีสิ่งของขนาดเล็กอยู่ด้านหน้า และสิ่งของขนาดใหญ่ อยู่ด้านหลัง เป็นการใช้ทัศนธาตุใดเพื่อสร้างมิติ?', 'การใช้ขนาด (Size) ที่แตกต่างกันของวัตถุ โดยวัตถุที่อยู่ใกล้จะมีขนาดใหญ่กว่าวัตถุที่อยู่ไกล เป็นเทคนิคในการสร้างมิติและความลึกให้กับภาพ', '2025-03-22 09:22:27', '2025-03-22 09:22:27'),
(466, 35, 'ข้อใด *ไม่ใช่* ชนิดข้อมูลพื้นฐานในภาษา Python?', 'ใน Python, `array` ไม่ใช่ชนิดข้อมูลพื้นฐาน  เราใช้ `list` แทน  `array` มักจะมาจาก library ภายนอก เช่น NumPy', '2025-03-22 14:53:51', '2025-03-22 14:53:51'),
(467, 35, 'ข้อใดคือตัวดำเนินการ (operator) สำหรับการหารเอาเศษ (modulo)?', 'ตัวดำเนินการ `%` ใช้สำหรับการหารเอาเศษ (modulo) ซึ่งจะคืนค่าเศษที่เหลือจากการหาร', '2025-03-22 14:53:51', '2025-03-22 14:53:51'),
(468, 35, 'ข้อใดคือคำสั่งที่ใช้ในการแสดงผลลัพธ์ออกทางหน้าจอ?', 'คำสั่ง `print()` ใช้ในการแสดงผลลัพธ์ (output) ออกทางหน้าจอ', '2025-03-22 14:53:51', '2025-03-22 14:53:51'),
(469, 35, 'ข้อใดคือ syntax ที่ถูกต้องสำหรับการกำหนดเงื่อนไข `if` ใน Python?', 'ใน Python, เงื่อนไข `if` จะตามด้วย colon (`:`) และ code block ที่จะทำงานภายใต้เงื่อนไขนั้นจะต้องมีการย่อหน้า (indentation)', '2025-03-22 14:53:51', '2025-03-22 14:53:51'),
(470, 35, 'ข้อใดคือ syntax ที่ถูกต้องสำหรับการวนซ้ำ (loop) โดยใช้ `for` loop ใน Python?', 'ใน Python, `for` loop มักใช้คู่กับ `range()` หรือ iterable object อื่นๆ และ code block ที่จะทำงานใน loop จะต้องมีการย่อหน้า', '2025-03-22 14:53:51', '2025-03-22 14:53:51'),
(471, 35, 'ข้อใดคือวิธีการสร้าง list ใน Python?', 'list ใน Python สร้างโดยใช้วงเล็บเหลี่ยม `[]` และคั่นสมาชิกแต่ละตัวด้วย comma', '2025-03-22 14:53:51', '2025-03-22 14:53:51'),
(472, 35, 'ข้อใดคือวิธีการสร้าง tuple ใน Python?', 'tuple ใน Python สร้างโดยใช้วงเล็บ `()` และคั่นสมาชิกแต่ละตัวด้วย comma  แม้ว่าการละเว้นวงเล็บในบางกรณีจะยังคงสร้าง tuple ได้ แต่การใช้วงเล็บจะทำให้ code ชัดเจนขึ้น', '2025-03-22 14:53:51', '2025-03-22 14:53:51'),
(473, 35, 'ข้อใดคือวิธีการสร้าง dictionary ใน Python?', 'dictionary ใน Python สร้างโดยใช้วงเล็บปีกกา `{}` และสมาชิกแต่ละตัวอยู่ในรูป key-value pair โดยคั่นด้วย colon (`:`) และคั่นแต่ละ pair ด้วย comma', '2025-03-22 14:53:51', '2025-03-22 14:53:51'),
(474, 35, 'ข้อใด *ไม่ใช่* คุณสมบัติของตัวแปรใน Python?', 'ชื่อตัวแปรใน Python *ไม่สามารถ* ขึ้นต้นด้วยตัวเลขได้ ต้องขึ้นต้นด้วยตัวอักษร (a-z, A-Z) หรือ underscore (_)', '2025-03-22 14:53:51', '2025-03-22 14:53:51'),
(475, 35, 'ฟังก์ชัน `len()` ใช้ทำอะไรกับ string?', 'ฟังก์ชัน `len()` ใช้คืนค่าความยาว (จำนวนตัวอักษร) ของ string', '2025-03-22 14:53:51', '2025-03-22 14:53:51'),
(476, 36, 'อาณาจักรสุโขทัยก่อตั้งขึ้นประมาณปี พ.ศ. ใด?', 'อาณาจักรสุโขทัยก่อตั้งขึ้นประมาณปี พ.ศ. 1800 โดยประมาณ', '2025-03-23 05:51:15', '2025-03-23 05:51:15'),
(477, 36, 'ใครคือปฐมกษัตริย์แห่งอาณาจักรสุโขทัย?', 'พ่อขุนศรีอินทราทิตย์ทรงเป็นปฐมกษัตริย์แห่งอาณาจักรสุโขทัย', '2025-03-23 05:51:15', '2025-03-23 05:51:15'),
(478, 36, 'ข้อใดคือสิ่งประดิษฐ์ที่สำคัญในสมัยสุโขทัย?', 'ตัวอักษรไทยถูกประดิษฐ์ขึ้นในสมัยสุโขทัย โดยพ่อขุนรามคำแหงมหาราช', '2025-03-23 05:51:15', '2025-03-23 05:51:15'),
(479, 36, 'กษัตริย์องค์ใดในสมัยสุโขทัยที่ทรงมีบทบาทสำคัญในการเผยแผ่พระพุทธศาสนา?', 'พระมหาธรรมราชาที่ 1 (ลิไท) ทรงเป็นกษัตริย์ที่ทรงมีบทบาทสำคัญในการเผยแผ่พระพุทธศาสนาในสมัยสุโขทัย', '2025-03-23 05:51:15', '2025-03-23 05:51:15'),
(480, 36, 'เมืองใดเป็นเมืองหลวงแห่งแรกของอาณาจักรสุโขทัย?', 'สุโขทัยเป็นเมืองหลวงแห่งแรกของอาณาจักรสุโขทัย', '2025-03-23 05:51:15', '2025-03-23 05:51:15'),
(481, 36, 'หลักศิลาจารึกใดที่ให้ข้อมูลสำคัญเกี่ยวกับประวัติศาสตร์สุโขทัย?', 'ศิลาจารึกพ่อขุนรามคำแหงเป็นหลักฐานสำคัญที่ให้ข้อมูลเกี่ยวกับประวัติศาสตร์สุโขทัย', '2025-03-23 05:51:15', '2025-03-23 05:51:15'),
(482, 36, 'อาณาจักรสุโขทัยมีความสัมพันธ์ทางการค้ากับอาณาจักรใด?', 'อาณาจักรสุโขทัยมีความสัมพันธ์ทางการค้ากับอาณาจักรจีน', '2025-03-23 05:51:15', '2025-03-23 05:51:15'),
(483, 36, 'พระพุทธรูปปางใดที่นิยมสร้างในสมัยสุโขทัย?', 'พระพุทธรูปปางมารวิชัยเป็นปางที่นิยมสร้างในสมัยสุโขทัย', '2025-03-23 05:51:15', '2025-03-23 05:51:15'),
(484, 36, 'อาณาจักรใดที่ผนวกอาณาจักรสุโขทัยเข้าไปเป็นส่วนหนึ่ง?', 'อาณาจักรอยุธยาผนวกอาณาจักรสุโขทัยเข้าไปเป็นส่วนหนึ่ง', '2025-03-23 05:51:15', '2025-03-23 05:51:15'),
(485, 36, 'ข้อใดไม่ใช่ลักษณะเด่นของศิลปะสุโขทัย?', 'ศิลปะสุโขทัยมีลักษณะเด่นคือ ความอ่อนช้อย, ความสมจริง, และความสง่างาม ไม่ใช่ความแข็งกระด้าง', '2025-03-23 05:51:15', '2025-03-23 05:51:15'),
(486, 37, 'ธาตุใดต่อไปนี้เป็นธาตุแฮโลเจน?', 'คลอรีน (Cl) อยู่ในหมู่ 17 ของตารางธาตุ ซึ่งเป็นหมู่ของธาตุแฮโลเจน', '2025-03-23 12:00:09', '2025-03-23 12:00:09'),
(487, 37, 'ธาตุใดต่อไปนี้มีค่าอิเล็กโทรเนกาติวิตีสูงที่สุด?', 'ฟลูออรีน (F) เป็นธาตุที่มีค่าอิเล็กโทรเนกาติวิตีสูงที่สุดในตารางธาตุ', '2025-03-23 12:00:09', '2025-03-23 12:00:09'),
(488, 37, 'ธาตุใดต่อไปนี้เป็นโลหะแอลคาไล?', 'โพแทสเซียม (K) อยู่ในหมู่ 1 ของตารางธาตุ ซึ่งเป็นหมู่ของโลหะแอลคาไล', '2025-03-23 12:00:09', '2025-03-23 12:00:09'),
(489, 37, 'แนวโน้มขนาดอะตอมในตารางธาตุเป็นอย่างไร เมื่อพิจารณาจากซ้ายไปขวา?', 'ขนาดอะตอมลดลงจากซ้ายไปขวา เนื่องจากแรงดึงดูดของนิวเคลียสต่ออิเล็กตรอนเพิ่มขึ้น', '2025-03-23 12:00:09', '2025-03-23 12:00:09'),
(490, 37, 'ธาตุใดต่อไปนี้เป็นก๊าซเฉื่อย (Noble Gas)?', 'นีออน (Ne) อยู่ในหมู่ 18 ของตารางธาตุ ซึ่งเป็นหมู่ของก๊าซเฉื่อย', '2025-03-23 12:00:09', '2025-03-23 12:00:09'),
(491, 37, 'เลขอะตอมของธาตุคืออะไร?', 'เลขอะตอมคือจำนวนโปรตอนในนิวเคลียสของอะตอม ซึ่งเป็นตัวกำหนดชนิดของธาตุ', '2025-03-23 12:00:09', '2025-03-23 12:00:09'),
(492, 37, 'ไอโซโทปของธาตุเดียวกันมีอะไรที่แตกต่างกัน?', 'ไอโซโทปของธาตุเดียวกันมีจำนวนโปรตอนเท่ากัน แต่มีจำนวนนิวตรอนแตกต่างกัน', '2025-03-23 12:00:09', '2025-03-23 12:00:09'),
(493, 37, 'ธาตุในหมู่ใดต่อไปนี้มีแนวโน้มที่จะสร้างไอออนที่มีประจุ +2?', 'ธาตุในหมู่ 2 มีเวเลนซ์อิเล็กตรอน 2 ตัว และมีแนวโน้มที่จะเสียอิเล็กตรอน 2 ตัว เพื่อให้ได้ประจุ +2', '2025-03-23 12:00:09', '2025-03-23 12:00:09'),
(494, 37, 'สมบัติใดต่อไปนี้เปลี่ยนแปลงตามคาบในตารางธาตุ?', 'พลังงานไอออไนเซชัน (energy required to remove an electron) increases across a period and generally decreases down a group.', '2025-03-23 12:00:09', '2025-03-23 12:00:09'),
(495, 37, 'ธาตุทรานซิชันส่วนใหญ่อยู่ในบล็อกใดของตารางธาตุ?', 'ธาตุทรานซิชันส่วนใหญ่อยู่ใน d-block ของตารางธาตุ', '2025-03-23 12:00:09', '2025-03-23 12:00:09'),
(496, 38, 'พื้นที่ของสี่เหลี่ยมจัตุรัสที่มีด้านยาว 5 เซนติเมตร คือเท่าใด?', 'พื้นที่สี่เหลี่ยมจัตุรัส = ด้าน x ด้าน = 5 x 5 = 25 ตารางเซนติเมตร', '2025-03-23 12:02:01', '2025-03-23 12:02:01'),
(497, 38, 'พื้นที่ของสี่เหลี่ยมผืนผ้าที่มีความยาว 8 เมตร และความกว้าง 4 เมตร คือเท่าใด?', 'พื้นที่สี่เหลี่ยมผืนผ้า = ความยาว x ความกว้าง = 8 x 4 = 32 ตารางเมตร', '2025-03-23 12:02:01', '2025-03-23 12:02:01'),
(498, 38, 'พื้นที่ของสามเหลี่ยมที่มีฐานยาว 10 เซนติเมตร และสูง 6 เซนติเมตร คือเท่าใด?', 'พื้นที่สามเหลี่ยม = (1/2) x ฐาน x สูง = (1/2) x 10 x 6 = 30 ตารางเซนติเมตร', '2025-03-23 12:02:01', '2025-03-23 12:02:01'),
(499, 38, 'พื้นที่ของวงกลมที่มีรัศมี 7 เซนติเมตร คือเท่าใด? (กำหนดให้ π = 22/7)', 'พื้นที่วงกลม = πr² = (22/7) x 7 x 7 = 154 ตารางเซนติเมตร', '2025-03-23 12:02:01', '2025-03-23 12:02:01'),
(500, 38, 'พื้นที่ของรูปสี่เหลี่ยมคางหมูที่มีความสูง 5 เซนติเมตร ด้านคู่ขนานยาว 6 เซนติเมตร และ 8 เซนติเมตร คือเท่าใด?', 'พื้นที่สี่เหลี่ยมคางหมู = (1/2) x สูง x (ผลบวกของด้านคู่ขนาน) = (1/2) x 5 x (6 + 8) = 35 ตารางเซนติเมตร', '2025-03-23 12:02:01', '2025-03-23 12:02:01'),
(501, 38, 'ถ้าสี่เหลี่ยมจัตุรัสมีพื้นที่ 64 ตารางเมตร ด้านแต่ละด้านยาวเท่าใด?', 'พื้นที่สี่เหลี่ยมจัตุรัส = ด้าน x ด้าน ดังนั้น ด้าน = √64 = 8 เมตร', '2025-03-23 12:02:01', '2025-03-23 12:02:01'),
(502, 38, 'พื้นที่ของรูปว่าวที่มีเส้นทแยงมุมยาว 12 เซนติเมตร และ 8 เซนติเมตร คือเท่าใด?', 'พื้นที่รูปว่าว = (1/2) x ผลคูณของเส้นทแยงมุม = (1/2) x 12 x 8 = 48 ตารางเซนติเมตร', '2025-03-23 12:02:01', '2025-03-23 12:02:01'),
(503, 38, 'สี่เหลี่ยมขนมเปียกปูนมีฐานยาว 15 เซนติเมตร และสูง 6 เซนติเมตร พื้นที่ของสี่เหลี่ยมขนมเปียกปูนนี้คือเท่าใด?', 'พื้นที่สี่เหลี่ยมขนมเปียกปูน = ฐาน x สูง = 15 x 6 = 90 ตารางเซนติเมตร', '2025-03-23 12:02:01', '2025-03-23 12:02:01'),
(504, 38, 'รูปสี่เหลี่ยมด้านขนานมีฐานยาว 9 เมตร และสูง 4 เมตร พื้นที่เท่ากับข้อใด', 'พื้นที่สี่เหลี่ยมด้านขนาน = ฐาน x สูง = 9 x 4 = 36 ตารางเมตร', '2025-03-23 12:02:01', '2025-03-23 12:02:01'),
(505, 38, 'รูปหกเหลี่ยมด้านเท่ามุมเท่า ยาวด้านละ 4 เซนติเมตร จะสามารถแบ่งเป็นรูปสามเหลี่ยมด้านเท่าได้กี่รูป และพื้นที่รวมคือเท่าใด(ไม่ต้องคำนวณหาตัวเลข แค่ทราบจำนวนสามเหลี่ยม)', 'รูปหกเหลี่ยมด้านเท่ามุมเท่า สามารถแบ่งเป็นรูปสามเหลี่ยมด้านเท่าได้ 6 รูป โดยลากเส้นจากจุดศูนย์กลางไปยังแต่ละมุม', '2025-03-23 12:02:01', '2025-03-23 12:02:01'),
(506, 39, 'คำราชาศัพท์คำใดใช้สำหรับ \'กิน\' ของพระมหากษัตริย์?', '\'เสวย\' เป็นคำราชาศัพท์ที่ใช้สำหรับ \'กิน\' ของพระมหากษัตริย์', '2025-03-23 12:14:55', '2025-03-23 12:14:55'),
(507, 39, 'ข้อใดคือคำราชาศัพท์ของคำว่า \'ตาย\' ที่ใช้กับพระบรมวงศานุวงศ์ชั้นสูง?', '\'สิ้นพระชนม์\' ใช้สำหรับพระบรมวงศานุวงศ์ชั้นสูง', '2025-03-23 12:14:55', '2025-03-23 12:14:55'),
(508, 39, 'คำราชาศัพท์คำใดใช้เมื่อพระมหากษัตริย์ \'ให้\' สิ่งของ?', '\'ประทาน\' เป็นคำราชาศัพท์ที่ถูกต้องสำหรับการ \'ให้\' ของพระมหากษัตริย์', '2025-03-23 12:14:55', '2025-03-23 12:14:55'),
(509, 39, 'คำราชาศัพท์ใดที่ใช้เรียก \'บ้าน\' ของพระมหากษัตริย์?', '\'พระราชวัง\' เป็นคำราชาศัพท์ที่ใช้เรียก \'บ้าน\' ของพระมหากษัตริย์', '2025-03-23 12:14:55', '2025-03-23 12:14:55'),
(510, 39, 'ถ้าต้องการกล่าวว่า \'ป่วย\' ของพระสงฆ์ ควรใช้คำใด?', '\'อาพาธ\' เป็นคำที่ใช้เมื่อพระสงฆ์ \'ป่วย\'', '2025-03-23 12:14:55', '2025-03-23 12:14:55'),
(511, 39, 'คำราชาศัพท์ใดใช้สำหรับ \'หัว\' ของพระมหากษัตริย์?', '\'เศียร\' เป็นคำราชาศัพท์ที่ใช้สำหรับ \'หัว\' ของพระมหากษัตริย์', '2025-03-23 12:14:55', '2025-03-23 12:14:55'),
(512, 39, 'คำใดใช้เป็นคำลงท้ายเมื่อพูดกับพระมหากษัตริย์?', '\'พะยะค่ะ/พระพุทธเจ้าค่ะ\' เป็นคำลงท้ายที่ใช้เมื่อพูดกับพระมหากษัตริย์', '2025-03-23 12:14:55', '2025-03-23 12:14:55'),
(513, 39, 'เมื่อต้องการกล่าวถึง \'ลูก\' ของพระมหากษัตริย์ ควรใช้คำใด?', '\'โอรส/ธิดา\' เป็นคำราชาศัพท์ที่ใช้เรียก \'ลูก\' ของพระมหากษัตริย์', '2025-03-23 12:14:55', '2025-03-23 12:14:55'),
(514, 39, 'คำราชาศัพท์ของ \'จดหมาย\' คือข้อใด?', '\'พระราชสาส์น\' เป็นคำราชาศัพท์ที่ใช้เรียก \'จดหมาย\' ที่เกี่ยวข้องกับพระมหากษัตริย์', '2025-03-23 12:14:55', '2025-03-23 12:14:55'),
(515, 39, 'ข้อใดเป็นการใช้คำราชาศัพท์ที่ไม่ถูกต้อง?', 'การใช้คำว่า \'นอนหลับ\' กับพระมหากษัตริย์ไม่ถูกต้อง ควรใช้ \'ทรงพระบรรทม\'', '2025-03-23 12:14:55', '2025-03-23 12:14:55'),
(516, 40, 'อาณาจักรสุโขทัยก่อตั้งขึ้นเมื่อใด?', 'อาณาจักรสุโขทัยได้รับการสถาปนาขึ้นในปี พ.ศ. 1792 โดยพ่อขุนศรีอินทราทิตย์', '2025-03-23 12:17:34', '2025-03-23 12:17:34'),
(517, 40, 'ใครคือปฐมกษัตริย์แห่งอาณาจักรสุโขทัย?', 'พ่อขุนศรีอินทราทิตย์ทรงเป็นปฐมกษัตริย์แห่งอาณาจักรสุโขทัย', '2025-03-23 12:17:34', '2025-03-23 12:17:34'),
(518, 40, 'ศิลาจารึกหลักที่ 1 เป็นผลงานของใคร?', 'ศิลาจารึกหลักที่ 1 หรือศิลาจารึกพ่อขุนรามคำแหง เป็นผลงานของพ่อขุนรามคำแหงมหาราช', '2025-03-23 12:17:34', '2025-03-23 12:17:34'),
(519, 40, 'ตัวอักษรไทยถูกประดิษฐ์ขึ้นในสมัยของกษัตริย์พระองค์ใด?', 'พ่อขุนรามคำแหงมหาราชทรงประดิษฐ์อักษรไทยขึ้นเมื่อปี พ.ศ. 1826', '2025-03-23 12:17:34', '2025-03-23 12:17:34'),
(520, 40, 'พระพุทธศาสนานิกายใดที่เจริญรุ่งเรืองในสมัยสุโขทัย?', 'พระพุทธศาสนานิกายเถรวาท เจริญรุ่งเรืองมากในสมัยสุโขทัย โดยเฉพาะอย่างยิ่งในรัชสมัยพระมหาธรรมราชาที่ 1 (ลิไท)', '2025-03-23 12:17:34', '2025-03-23 12:17:34'),
(521, 40, 'ใครคือผู้แต่งหนังสือ \'ไตรภูมิพระร่วง\'?', 'พระมหาธรรมราชาที่ 1 (ลิไท) ทรงนิพนธ์หนังสือ \'ไตรภูมิพระร่วง\' ซึ่งเป็นวรรณกรรมทางศาสนาที่สำคัญ', '2025-03-23 12:17:34', '2025-03-23 12:17:34'),
(522, 40, 'สุโขทัยมีความสัมพันธ์ทางการทูตกับประเทศใดบ้าง?', 'สุโขทัยมีความสัมพันธ์ทางการทูตและการค้ากับจีนอย่างใกล้ชิด', '2025-03-23 12:17:34', '2025-03-23 12:17:34'),
(523, 40, 'อาณาจักรใดที่เข้ามามีบทบาทและผนวกสุโขทัยเข้าเป็นส่วนหนึ่ง?', 'อาณาจักรอยุธยาค่อยๆ ขยายอำนาจและผนวกสุโขทัยเข้าเป็นส่วนหนึ่งในที่สุด', '2025-03-23 12:17:34', '2025-03-23 12:17:34'),
(524, 40, 'เมืองหลวงของอาณาจักรสุโขทัยคือเมืองใด?', 'เมืองสุโขทัยเป็นเมืองหลวงของอาณาจักรสุโขทัย', '2025-03-23 12:17:34', '2025-03-23 12:17:34'),
(525, 40, 'ข้อใดไม่ใช่ลักษณะเด่นของศิลปะสุโขทัย?', 'ประติมากรรมแบบทวารวดีเป็นศิลปะที่เกิดขึ้นก่อนสมัยสุโขทัย ลักษณะเด่นของศิลปะสุโขทัยคือพระพุทธรูปปางมารวิชัย เจดีย์ทรงลังกา และลายไทยแบบกนก', '2025-03-23 12:17:34', '2025-03-23 12:17:34'),
(526, 41, 'หัวใจของมนุษย์มีกี่ห้อง?', 'หัวใจของมนุษย์มี 4 ห้อง: เอเตรียมขวา เอเตรียมซ้าย เวนตริเคิลขวา และเวนตริเคิลซ้าย', '2025-03-24 04:39:03', '2025-03-24 04:39:03'),
(527, 41, 'หลอดเลือดชนิดใดที่นำเลือดออกจากหัวใจ?', 'หลอดเลือดแดง (Artery) ทำหน้าที่นำเลือดออกจากหัวใจไปยังส่วนต่างๆ ของร่างกาย', '2025-03-24 04:39:03', '2025-03-24 04:39:03'),
(528, 41, 'หลอดเลือดชนิดใดที่มีหน้าที่แลกเปลี่ยนแก๊สและสารอาหารกับเซลล์?', 'หลอดเลือดฝอย (Capillary) เป็นหลอดเลือดขนาดเล็กที่แทรกอยู่ระหว่างเซลล์ ทำหน้าที่แลกเปลี่ยนแก๊สออกซิเจน คาร์บอนไดออกไซด์ สารอาหาร และของเสีย', '2025-03-24 04:39:03', '2025-03-24 04:39:03'),
(529, 41, 'เลือดที่ออกจากหัวใจห้องล่างขวา (Right ventricle) จะไหลไปยังที่ใด?', 'เลือดที่ออกจากหัวใจห้องล่างขวา (Right ventricle) จะถูกส่งไปยังปอดเพื่อแลกเปลี่ยนแก๊ส (รับออกซิเจนและปล่อยคาร์บอนไดออกไซด์)', '2025-03-24 04:39:03', '2025-03-24 04:39:03'),
(530, 41, 'ส่วนประกอบใดของเลือดที่ทำหน้าที่ในการขนส่งออกซิเจน?', 'เม็ดเลือดแดง (Red blood cells) มีฮีโมโกลบิน ซึ่งเป็นโปรตีนที่จับกับออกซิเจนและขนส่งไปยังส่วนต่างๆ ของร่างกาย', '2025-03-24 04:39:03', '2025-03-24 04:39:03'),
(531, 41, 'ลิ้นหัวใจทำหน้าที่อะไร?', 'ลิ้นหัวใจมีหน้าที่สำคัญในการป้องกันไม่ให้เลือดไหลย้อนกลับในขณะที่หัวใจบีบตัวและคลายตัว', '2025-03-24 04:39:03', '2025-03-24 04:39:03');
INSERT INTO `questions` (`id`, `quiz_id`, `question_text`, `explanation`, `created_at`, `updated_at`) VALUES
(532, 41, 'เส้นเลือดแดงใหญ่เอออร์ตา (Aorta) นำเลือดไปสู่ส่วนใดของร่างกาย?', 'เส้นเลือดแดงใหญ่เอออร์ตา (Aorta) เป็นเส้นเลือดแดงที่ใหญ่ที่สุดในร่างกาย นำเลือดแดงที่ออกจากหัวใจห้องล่างซ้ายไปสู่ส่วนต่างๆ ของร่างกาย', '2025-03-24 04:39:03', '2025-03-24 04:39:03'),
(533, 41, 'อะไรคือความดันโลหิต?', 'ความดันโลหิตคือแรงดันที่เกิดจากเลือดที่ไหลเวียนในหลอดเลือดแดง มีสองค่าคือ ความดันซิสโตลิก (ขณะหัวใจบีบตัว) และความดันไดแอสโตลิก (ขณะหัวใจคลายตัว)', '2025-03-24 04:39:03', '2025-03-24 04:39:03'),
(534, 41, 'หน้าที่หลักของเกล็ดเลือดคืออะไร?', 'เกล็ดเลือด (Platelets) มีบทบาทสำคัญในการแข็งตัวของเลือดเพื่อหยุดการไหลของเลือดเมื่อเกิดบาดแผล', '2025-03-24 04:39:03', '2025-03-24 04:39:03'),
(535, 41, 'หัวใจห้องใดที่รับเลือดที่มีออกซิเจนจากปอด?', 'หัวใจห้องบนซ้าย (Left atrium) รับเลือดที่มีออกซิเจนจากปอดผ่านทางหลอดเลือดดำปอด (Pulmonary veins)', '2025-03-24 04:39:03', '2025-03-24 04:39:03'),
(536, 42, 'ปฏิกิริยาออกซิเดชันคืออะไร?', 'ปฏิกิริยาออกซิเดชันคือปฏิกิริยาที่อะตอม, ไอออน หรือโมเลกุลสูญเสียอิเล็กตรอน', '2025-03-24 08:36:31', '2025-03-24 08:36:31'),
(537, 42, 'ปฏิกิริยารีดักชันคืออะไร?', 'ปฏิกิริยารีดักชันคือปฏิกิริยาที่อะตอม, ไอออน หรือโมเลกุลรับอิเล็กตรอน', '2025-03-24 08:36:31', '2025-03-24 08:36:31'),
(538, 42, 'สารใดต่อไปนี้เป็นตัวออกซิไดซ์ที่ดี?', 'ตัวออกซิไดซ์คือสารที่รับอิเล็กตรอนจากสารอื่น, ดังนั้นสารที่รับอิเล็กตรอนได้ง่ายจึงเป็นตัวออกซิไดซ์ที่ดี', '2025-03-24 08:36:31', '2025-03-24 08:36:31'),
(539, 42, 'สารใดต่อไปนี้เป็นตัวรีดิวซ์ที่ดี?', 'ตัวรีดิวซ์คือสารที่ให้อิเล็กตรอนแก่สารอื่น, ดังนั้นสารที่สูญเสียอิเล็กตรอนได้ง่ายจึงเป็นตัวรีดิวซ์ที่ดี', '2025-03-24 08:36:31', '2025-03-24 08:36:31'),
(540, 42, 'เลขออกซิเดชันของ O ใน H₂O คืออะไร?', 'H มีเลขออกซิเดชัน +1 และมี 2 อะตอม รวมเป็น +2 ดังนั้น O ต้องมีเลขออกซิเดชัน -2 เพื่อให้ผลรวมเป็น 0', '2025-03-24 08:36:31', '2025-03-24 08:36:31'),
(541, 42, 'เลขออกซิเดชันของ Mn ใน KMnO₄ คืออะไร?', 'K มีเลขออกซิเดชัน +1 และ O มีเลขออกซิเดชัน -2 (มี 4 อะตอม รวมเป็น -8) ดังนั้น Mn ต้องมีเลขออกซิเดชัน +7 เพื่อให้ผลรวมเป็น 0 (+1 + Mn - 8 = 0)', '2025-03-24 08:36:31', '2025-03-24 08:36:31'),
(542, 42, 'ในปฏิกิริยา Zn(s) + Cu²⁺(aq) → Zn²⁺(aq) + Cu(s) สารใดถูกออกซิไดซ์?', 'Zn เปลี่ยนเป็น Zn²⁺ โดยการสูญเสียอิเล็กตรอน ดังนั้น Zn ถูกออกซิไดซ์', '2025-03-24 08:36:31', '2025-03-24 08:36:31'),
(543, 42, 'ในปฏิกิริยา Zn(s) + Cu²⁺(aq) → Zn²⁺(aq) + Cu(s) สารใดถูกรีดิวซ์?', 'Cu²⁺ เปลี่ยนเป็น Cu โดยการรับอิเล็กตรอน ดังนั้น Cu²⁺ ถูกรีดิวซ์', '2025-03-24 08:36:31', '2025-03-24 08:36:31'),
(544, 42, 'ข้อใดคือประโยชน์ของปฏิกิริยาออกซิเดชัน-รีดักชัน?', 'ปฏิกิริยาออกซิเดชัน-รีดักชันใช้ในการผลิตกระแสไฟฟ้าในแบตเตอรี่ โดยการถ่ายโอนอิเล็กตรอนระหว่างสารเคมี', '2025-03-24 08:36:31', '2025-03-24 08:36:31'),
(545, 42, 'ข้อใดคือสมการรีดอกซ์ (redox reaction)?', 'สมการ 2H₂(g) + O₂(g) → 2H₂O(g) มีการเปลี่ยนแปลงเลขออกซิเดชันของ H และ O ดังนั้นเป็นปฏิกิริยารีดอกซ์', '2025-03-24 08:36:31', '2025-03-24 08:36:31'),
(546, 43, 'ข้อใดคือกฎของบอยล์ (Boyle\'s Law)?', 'กฎของบอยล์กล่าวว่า ที่อุณหภูมิคงที่ ความดันของแก๊สแปรผกผันกับปริมาตร', '2025-03-24 08:37:03', '2025-03-24 08:37:03'),
(547, 43, 'ข้อใดคือกฎของชาร์ลส์ (Charles\'s Law)?', 'กฎของชาร์ลส์กล่าวว่า ที่ความดันคงที่ ปริมาตรของแก๊สแปรผันตรงกับอุณหภูมิสัมบูรณ์', '2025-03-24 08:37:03', '2025-03-24 08:37:03'),
(548, 43, 'ข้อใดคือกฎของเกย์-ลูสแซก (Gay-Lussac\'s Law)?', 'กฎของเกย์-ลูสแซกกล่าวว่า ที่ปริมาตรคงที่ ความดันของแก๊สแปรผันตรงกับอุณหภูมิสัมบูรณ์', '2025-03-24 08:37:03', '2025-03-24 08:37:03'),
(549, 43, 'กฎของอาโวกาโดร (Avogadro\'s Law) กล่าวว่าอย่างไร?', 'กฎของอาโวกาโดรกล่าวว่า ที่ความดันและอุณหภูมิคงที่ ปริมาตรของแก๊สแปรผันตรงกับจำนวนโมล', '2025-03-24 08:37:03', '2025-03-24 08:37:03'),
(550, 43, 'ข้อใดคือสมการกฎแก๊สอุดมคติ (Ideal Gas Law)?', 'สมการกฎแก๊สอุดมคติคือ PV = nRT โดยที่ P คือความดัน, V คือปริมาตร, n คือจำนวนโมล, R คือค่าคงที่ของแก๊ส, และ T คืออุณหภูมิสัมบูรณ์', '2025-03-24 08:37:03', '2025-03-24 08:37:03'),
(551, 43, 'จากสมการต่อเนื่อง (Continuity Equation) ในพลศาสตร์ของของไหล ข้อใดถูกต้อง?', 'สมการต่อเนื่อง (A₁V₁ = A₂V₂) แสดงว่าอัตราการไหลของของไหลคงที่ในท่อที่มีพื้นที่หน้าตัดเปลี่ยนแปลง', '2025-03-24 08:37:03', '2025-03-24 08:37:03'),
(552, 43, 'ข้อใดคือสมการแบร์นูลลี (Bernoulli\'s Equation)?', 'สมการแบร์นูลลี (P + ρgh + 1/2ρv² = คงที่) แสดงถึงความสัมพันธ์ระหว่างความดัน ความสูง และความเร็วของของไหล', '2025-03-24 08:37:04', '2025-03-24 08:37:04'),
(553, 43, 'ความหนืด (Viscosity) คืออะไร?', 'ความหนืดคือสมบัติของของไหลที่แสดงถึงความต้านทานต่อการไหล (Internal friction)', '2025-03-24 08:37:04', '2025-03-24 08:37:04'),
(554, 43, 'อะไรคือความหมายของ \'ρ\' (rho) ในสมการแบร์นูลลี?', '\'ρ\' (rho) ในสมการแบร์นูลลีคือสัญลักษณ์แทนความหนาแน่นของของไหล', '2025-03-24 08:37:04', '2025-03-24 08:37:04'),
(555, 43, 'ปรากฏการณ์ใดที่อธิบายได้ด้วยหลักการของแบร์นูลลี?', 'การยกตัวของเครื่องบินสามารถอธิบายได้ด้วยหลักการของแบร์นูลลี โดยความเร็วลมที่ปีกด้านบนสูงกว่าด้านล่าง ทำให้เกิดความดันที่ต่ำกว่า และเกิดแรงยก', '2025-03-24 08:37:04', '2025-03-24 08:37:04'),
(566, 45, 'หน่วยพื้นฐานที่เล็กที่สุดของ DNA คืออะไร?', 'นิวคลีโอไทด์ประกอบด้วยน้ำตาล ดีออกซีไรโบส, หมู่ฟอสเฟต และเบสไนโตรเจน และเป็นหน่วยพื้นฐานของ DNA', '2025-03-26 07:04:29', '2025-03-26 07:04:29'),
(567, 45, 'เบสไนโตรเจนชนิดใดที่จับคู่กับอะดีนีน (Adenine) ใน DNA?', 'อะดีนีน (A) จับคู่กับไทมีน (T) ด้วยพันธะไฮโดรเจนสองพันธะใน DNA', '2025-03-26 07:04:29', '2025-03-26 07:04:29'),
(568, 45, 'กระบวนการใดที่ DNA สร้างสำเนาของตัวเอง?', 'การจำลอง DNA เป็นกระบวนการที่ DNA สร้างสำเนาของตัวเองเพื่อให้เซลล์ลูกแต่ละเซลล์มีข้อมูลทางพันธุกรรมที่สมบูรณ์', '2025-03-26 07:04:29', '2025-03-26 07:04:29'),
(569, 45, 'ยีนคืออะไร?', 'ยีนคือลำดับเฉพาะของ DNA ที่กำหนดลักษณะทางพันธุกรรมโดยการเข้ารหัสโปรตีน', '2025-03-26 07:04:29', '2025-03-26 07:04:29'),
(570, 45, 'โครโมโซมคืออะไร?', 'โครโมโซมเป็นโครงสร้างที่ประกอบด้วย DNA ที่ถูกพันรอบโปรตีนฮิสโตน และพบในนิวเคลียสของเซลล์', '2025-03-26 07:04:29', '2025-03-26 07:04:29'),
(571, 45, 'การถอดรหัส (Transcription) คือกระบวนการใด?', 'การถอดรหัสคือกระบวนการสร้าง RNA จาก DNA โดยใช้ DNA เป็นแม่แบบ', '2025-03-26 07:04:29', '2025-03-26 07:04:29'),
(572, 45, 'การแปลรหัส (Translation) เกิดขึ้นที่ส่วนใดของเซลล์?', 'การแปลรหัสเกิดขึ้นที่ไรโบโซม ซึ่งเป็นสถานที่ที่ RNA ถูกใช้เพื่อสร้างโปรตีน', '2025-03-26 07:04:29', '2025-03-26 07:04:29'),
(573, 45, 'ความแปรผันทางพันธุกรรมเกิดจากอะไร?', 'ความแปรผันทางพันธุกรรมเกิดจากการผ่าเหล่า (การเปลี่ยนแปลงในลำดับ DNA) และการรวมตัวใหม่ของยีนในระหว่างการสืบพันธุ์แบบอาศัยเพศ', '2025-03-26 07:04:29', '2025-03-26 07:04:29'),
(574, 45, 'อัลลีล (Allele) คืออะไร?', 'อัลลีลคือรูปแบบต่างๆ ของยีนที่ตำแหน่ง (locus) เดียวกันบนโครโมโซม', '2025-03-26 07:04:29', '2025-03-26 07:04:29'),
(575, 45, 'ฟีโนไทป์ (Phenotype) หมายถึงอะไร?', 'ฟีโนไทป์คือลักษณะทางกายภาพ พฤติกรรม และสรีรวิทยาที่สังเกตได้ของสิ่งมีชีวิต ซึ่งเป็นผลมาจากการแสดงออกของยีนและอิทธิพลของสิ่งแวดล้อม', '2025-03-26 07:04:29', '2025-03-26 07:04:29'),
(576, 46, 'กระบวนการใดต่อไปนี้ที่ส่งผลกระทบต่อการเปลี่ยนแปลงไอโซโทปของออกซิเจน (δ18O) ในน้ำฝนมากที่สุดเมื่อเมฆฝนเคลื่อนที่จากทะเลสู่แผ่นดิน?', 'การควบแน่นเป็นกระบวนการที่ไอโซโทปหนักกว่า (18O) มีแนวโน้มที่จะควบแน่นก่อน ทำให้ฝนที่ตกในช่วงต้นมีค่า δ18O สูงกว่า เมื่อเมฆเคลื่อนที่ ไอโซโทปหนักจะถูกกำจัดออกไปเรื่อยๆ ทำให้ฝนที่ตกในภายหลังมีค่า δ18O ต่ำลง', '2025-03-29 09:07:38', '2025-03-29 09:07:38'),
(577, 46, 'ปัจจัยใดที่มีอิทธิพลต่ออัตราการคายระเหยน้ำรวม (Evapotranspiration) ในระบบนิเวศป่าดิบชื้นมากที่สุด?', 'ดัชนีพื้นที่ใบ (LAI) คือพื้นที่ใบทั้งหมดต่อหน่วยพื้นที่ดิน LAI ที่สูงแสดงถึงพื้นที่ผิวใบที่มากขึ้น ทำให้เกิดการคายน้ำมากขึ้น ส่งผลให้อัตราการคายระเหยน้ำรวมสูงขึ้นตามไปด้วย', '2025-03-29 09:07:38', '2025-03-29 09:07:38'),
(578, 46, 'การเปลี่ยนแปลงการใช้ที่ดินจากป่าไม้เป็นพื้นที่เกษตรกรรมส่งผลกระทบต่อวัฏจักรของน้ำในบริเวณนั้นอย่างไร?', 'การเปลี่ยนแปลงเป็นพื้นที่เกษตรกรรมมักจะทำให้ดินอัดแน่นมากขึ้น ลดความสามารถในการซึมน้ำของดิน ทำให้การไหลบ่าผิวดินเพิ่มขึ้น', '2025-03-29 09:07:38', '2025-03-29 09:07:38'),
(579, 46, 'ปรากฏการณ์เอลนีโญ (El Niño) ส่งผลกระทบต่อปริมาณน้ำฝนในภูมิภาคต่างๆ ของโลกอย่างไร?', 'เอลนีโญมักจะทำให้เกิดความแห้งแล้งในเอเชียตะวันออกเฉียงใต้และออสเตรเลีย เนื่องจากรูปแบบการไหลเวียนของบรรยากาศเปลี่ยนแปลงไป', '2025-03-29 09:07:38', '2025-03-29 09:07:38'),
(580, 46, 'กระบวนการใดที่ควบคุมการเคลื่อนที่ของน้ำบาดาลในชั้นหินอุ้มน้ำ (Aquifer) มากที่สุด?', 'ศักย์ของน้ำคือความแตกต่างของพลังงานศักย์ของน้ำระหว่างสองจุด ซึ่งเป็นตัวขับเคลื่อนการไหลของน้ำบาดาล น้ำจะไหลจากบริเวณที่มีศักย์ของน้ำสูงไปยังบริเวณที่มีศักย์ของน้ำต่ำ', '2025-03-29 09:07:38', '2025-03-29 09:07:38'),
(581, 46, 'ความเข้มข้นของสารละลายในน้ำ (Solute concentration) มีผลต่อศักย์ของน้ำอย่างไร?', 'สารละลายจะลดศักย์ของน้ำ เนื่องจากสารละลายจะลดความเข้มข้นของน้ำอิสระ (free water) ทำให้ศักย์ของน้ำลดลง', '2025-03-29 09:07:38', '2025-03-29 09:07:38'),
(582, 46, 'วิธีการใดที่แม่นยำที่สุดในการประมาณปริมาณน้ำฝนเฉลี่ยในพื้นที่ขนาดใหญ่ เช่น ลุ่มน้ำ?', 'เรดาร์ตรวจอากาศให้ข้อมูลปริมาณน้ำฝนครอบคลุมพื้นที่กว้างขวาง และสามารถประมาณค่าปริมาณน้ำฝนได้ค่อนข้างแม่นยำเมื่อเทียบกับวิธีการอื่นๆ โดยเฉพาะอย่างยิ่งในพื้นที่ที่มีความแปรปรวนของฝนสูง', '2025-03-29 09:07:38', '2025-03-29 09:07:38'),
(583, 46, 'การเปลี่ยนแปลงสภาพภูมิอากาศ (Climate Change) ส่งผลกระทบต่อการเกิดอุทกภัยอย่างไร?', 'การเปลี่ยนแปลงสภาพภูมิอากาศทำให้เกิดเหตุการณ์สภาพอากาศสุดขั้ว (extreme weather events) มากขึ้น เช่น ฝนตกหนัก ซึ่งนำไปสู่การเพิ่มขึ้นของความถี่และความรุนแรงของอุทกภัย', '2025-03-29 09:07:38', '2025-03-29 09:07:38'),
(584, 46, 'พารามิเตอร์ใดที่สำคัญที่สุดในการประเมินปริมาณน้ำท่า (Runoff) จากพื้นที่ลุ่มน้ำ?', 'ความชื้นในดินเป็นตัวแปรสำคัญที่ควบคุมปริมาณน้ำท่า ดินที่อิ่มตัวด้วยน้ำจะมีขีดความสามารถในการดูดซับน้ำน้อยลง ทำให้เกิดน้ำท่ามากขึ้นเมื่อมีฝนตก', '2025-03-29 09:07:38', '2025-03-29 09:07:38'),
(585, 46, 'บทบาทของความหลากหลายทางชีวภาพ (Biodiversity) ต่อการจัดการวัฏจักรของน้ำในระบบนิเวศคืออะไร?', 'ระบบนิเวศที่มีความหลากหลายทางชีวภาพสูง เช่น ป่าไม้ที่มีพืชหลายชนิด มีความสามารถในการดูดซับน้ำของดินสูงกว่า และลดการไหลบ่าผิวดิน ช่วยให้การจัดการวัฏจักรของน้ำมีประสิทธิภาพมากขึ้น', '2025-03-29 09:07:38', '2025-03-29 09:07:38'),
(586, 47, 'ข้อใดคือวิธีที่ถูกต้องในการประกาศตัวแปรใน JavaScript ที่มี scope เป็น block?', '`let` ใช้เพื่อประกาศตัวแปรที่มี scope เป็น block ในขณะที่ `var` มี scope เป็น function หรือ global ส่วน `const` ก็มี scope เป็น block แต่ใช้สำหรับค่าคงที่', '2025-03-30 12:32:26', '2025-03-30 12:32:26'),
(587, 47, 'ฟังก์ชัน `typeof` ใน JavaScript มีหน้าที่อะไร?', '`typeof` operator ใช้สำหรับตรวจสอบชนิดข้อมูลของตัวแปร เช่น \'string\', \'number\', \'boolean\', \'object\', \'function\', \'undefined\' เป็นต้น', '2025-03-30 12:32:26', '2025-03-30 12:32:26'),
(588, 47, 'ข้อใดคือความแตกต่างที่สำคัญระหว่าง `==` และ `===` ใน JavaScript?', '`==` ทำการเปรียบเทียบโดยแปลงชนิดข้อมูลหากจำเป็น ในขณะที่ `===` เปรียบเทียบโดยตรงทั้งค่าและชนิดข้อมูล ทำให้ `===` มีความเข้มงวดมากกว่า', '2025-03-30 12:32:26', '2025-03-30 12:32:26'),
(589, 47, 'การใช้งาน closure ใน JavaScript มีประโยชน์อย่างไร?', 'Closure ช่วยให้ฟังก์ชันสามารถ \'จำ\' และเข้าถึงตัวแปรจาก scope ที่ฟังก์ชันถูกสร้างขึ้น แม้ว่า scope นั้นจะหายไปแล้วก็ตาม ทำให้สามารถสร้าง state ส่วนตัวสำหรับฟังก์ชันได้', '2025-03-30 12:32:26', '2025-03-30 12:32:26'),
(590, 47, 'ข้อใดคือวิธีที่ถูกต้องในการเพิ่ม element ใหม่ไปยังท้าย array ใน JavaScript?', 'เมธอด `push()` ใช้สำหรับเพิ่ม element หนึ่งหรือหลาย element ไปยังท้าย array และคืนค่าความยาวใหม่ของ array', '2025-03-30 12:32:26', '2025-03-30 12:32:26'),
(591, 47, 'ใน JavaScript, `null` และ `undefined` มีความแตกต่างกันอย่างไร?', '`undefined` หมายถึงตัวแปรถูกประกาศแต่ยังไม่ได้รับค่า ส่วน `null` เป็นค่าที่ตั้งใจให้ตัวแปรไม่มีค่า', '2025-03-30 12:32:26', '2025-03-30 12:32:26'),
(592, 47, 'ข้อใดคือประโยชน์ของการใช้ strict mode (`\'use strict\';`) ใน JavaScript?', 'Strict mode ช่วยป้องกันการใช้งานที่ไม่ปลอดภัยหรือผิดพลาด เช่น การประกาศตัวแปรโดยไม่ได้ใช้ `var`, `let` หรือ `const`', '2025-03-30 12:32:26', '2025-03-30 12:32:26'),
(593, 47, 'ฟังก์ชัน `map()` ใน JavaScript มีหน้าที่อะไร?', '`map()` ใช้เพื่อสร้าง array ใหม่จาก array เดิม โดยทำการเปลี่ยนแปลงแต่ละ element ตามฟังก์ชันที่กำหนด', '2025-03-30 12:32:26', '2025-03-30 12:32:26'),
(594, 47, 'ข้อใดคือวิธีการจัดการ asynchronous operations ใน JavaScript ที่นิยมใช้กันมากที่สุดในปัจจุบัน?', 'Promises เป็นวิธีการจัดการ asynchronous operations ที่ช่วยหลีกเลี่ยง callback hell และทำให้ code อ่านง่ายขึ้น', '2025-03-30 12:32:26', '2025-03-30 12:32:26'),
(595, 47, '`async` และ `await` keywords ใน JavaScript มีไว้เพื่ออะไร?', '`async` และ `await` ทำให้การเขียน asynchronous code ดูเหมือน synchronous code ทำให้ code อ่านง่ายขึ้นและจัดการ errors ได้สะดวก', '2025-03-30 12:32:26', '2025-03-30 12:32:26'),
(596, 47, 'ข้อใดคือความหมายของ hoisting ใน JavaScript?', 'Hoisting คือกลไกที่ JavaScript ยก declarations (ไม่ใช่ initialization) ของตัวแปรและฟังก์ชันขึ้นไปไว้บนสุดของ scope ก่อนที่จะ execute code', '2025-03-30 12:32:26', '2025-03-30 12:32:26'),
(597, 47, 'JSON (JavaScript Object Notation) คืออะไร?', 'JSON เป็นรูปแบบข้อมูลที่มีโครงสร้างคล้ายกับ JavaScript object และใช้กันอย่างแพร่หลายสำหรับการแลกเปลี่ยนข้อมูลระหว่าง server และ client', '2025-03-30 12:32:26', '2025-03-30 12:32:26'),
(598, 47, 'ข้อใดคือวิธีการ copy object ใน JavaScript ที่ไม่ทำให้เกิด side effect (deep copy)?', '`JSON.parse(JSON.stringify(originalObject))` สร้าง deep copy โดยแปลง object เป็น string JSON แล้ว parse กลับมาเป็น object ใหม่ วิธีนี้จะสร้าง object ใหม่ที่ไม่มี reference ไปยัง object เดิม', '2025-03-30 12:32:26', '2025-03-30 12:32:26'),
(599, 47, 'ข้อใดคือความแตกต่างระหว่าง `forEach` loop และ `for...of` loop ใน JavaScript?', '`forEach` เป็น method ของ array เท่านั้น ในขณะที่ `for...of` สามารถใช้กับ iterable objects เช่น Map, Set, String ได้ นอกจากนี้ `break` และ `continue` ไม่สามารถใช้ใน `forEach` ได้', '2025-03-30 12:32:26', '2025-03-30 12:32:26'),
(600, 47, 'Template literals (``) ใน JavaScript มีประโยชน์อย่างไร?', 'Template literals ช่วยให้การสร้าง string ที่ซับซ้อนเป็นเรื่องง่าย โดยสามารถแทรกตัวแปรลงใน string โดยใช้ `${}` และสามารถเขียน string หลายบรรทัดได้โดยไม่ต้องใช้ escape characters', '2025-03-30 12:32:26', '2025-03-30 12:32:26'),
(601, 48, 'ข้อใดต่อไปนี้เป็นปัจจัยที่มีผลต่อสมดุลเคมี?', 'ความดันมีผลต่อสมดุลเคมี โดยเฉพาะในปฏิกิริยาที่มีแก๊สเกี่ยวข้อง การเปลี่ยนแปลงความดันจะทำให้สมดุลเลื่อนไปทางด้านที่มีโมลของแก๊สน้อยกว่าหรือมากกว่า เพื่อลดการเปลี่ยนแปลงนั้น', '2025-04-03 10:04:20', '2025-04-03 10:04:20'),
(602, 48, 'ค่าคงที่สมดุล (K) แสดงถึงอะไร?', 'ค่าคงที่สมดุล (K) คืออัตราส่วนของความเข้มข้นของผลิตภัณฑ์ยกกำลังสัมประสิทธิ์ของมัน หารด้วยความเข้มข้นของสารตั้งต้นยกกำลังสัมประสิทธิ์ของมัน ที่สภาวะสมดุล', '2025-04-03 10:04:20', '2025-04-03 10:04:20'),
(603, 48, 'Le Chatelier\'s principle กล่าวถึงอะไร?', 'Le Chatelier\'s principle กล่าวว่า หากระบบที่อยู่ในสภาวะสมดุลถูกรบกวน ระบบจะปรับตัวเพื่อลดผลกระทบของการรบกวนนั้น', '2025-04-03 10:04:20', '2025-04-03 10:04:20'),
(604, 48, 'ข้อใดเป็นปฏิกิริยาคายความร้อน?', 'ปฏิกิริยาคายความร้อนคือปฏิกิริยาที่ปล่อยพลังงานความร้อนสู่สิ่งแวดล้อม ทำให้สิ่งแวดล้อมมีอุณหภูมิสูงขึ้น', '2025-04-03 10:04:20', '2025-04-03 10:04:20'),
(605, 48, 'การเติมแก๊สเฉื่อย (เช่น He, Ne) ในระบบปิดที่มีปฏิกิริยาแก๊สเกิดขึ้น จะมีผลต่อสมดุลอย่างไร?', 'การเติมแก๊สเฉื่อยในปริมาตรคงที่ จะเพิ่มความดันรวม แต่ไม่เปลี่ยนแปลงความดันย่อยของสารอื่น ๆ ในปฏิกิริยา ดังนั้นจึงไม่มีผลต่อสมดุล', '2025-04-03 10:04:20', '2025-04-03 10:04:20'),
(606, 48, 'ถ้าค่า K > 1 แสดงว่าอะไร?', 'ค่า K > 1 หมายถึงความเข้มข้นของผลิตภัณฑ์ที่สภาวะสมดุลมีมากกว่าความเข้มข้นของสารตั้งต้น แสดงว่าปฏิกิริยาไปข้างหน้าได้ดี', '2025-04-03 10:04:20', '2025-04-03 10:04:20'),
(607, 48, 'ข้อใดคือความหมายของ \'สมดุลไดนามิก\' (dynamic equilibrium)?', 'สมดุลไดนามิกหมายถึงสถานะที่ปฏิกิริยาไปข้างหน้าและปฏิกิริยาย้อนกลับเกิดขึ้นด้วยอัตราเร็วที่เท่ากัน ทำให้ความเข้มข้นของสารตั้งต้นและผลิตภัณฑ์คงที่ แม้ว่าปฏิกิริยายังคงดำเนินต่อไป', '2025-04-03 10:04:20', '2025-04-03 10:04:20'),
(608, 48, 'ในการผลิตแอมโมเนีย (NH3) จากไนโตรเจน (N2) และไฮโดรเจน (H2) โดยใช้กระบวนการ Haber-Bosch ควรทำอย่างไรเพื่อเพิ่มผลผลิตแอมโมเนีย?', 'กระบวนการ Haber-Bosch เป็นปฏิกิริยาคายความร้อน การลดอุณหภูมิจะช่วยเพิ่มผลผลิต แต่ในทางปฏิบัติมักใช้ตัวเร่งปฏิกิริยาเพื่อเพิ่มอัตราการเกิดปฏิกิริยามากกว่า', '2025-04-03 10:04:20', '2025-04-03 10:04:20'),
(609, 48, 'ถ้า Q > K, ข้อใดถูกต้อง?', 'ถ้า Q (ผลหารปฏิกิริยา) มากกว่า K (ค่าคงที่สมดุล) หมายความว่ามีผลิตภัณฑ์มากเกินไปเมื่อเทียบกับสารตั้งต้น ดังนั้นปฏิกิริยาจะเลื่อนไปทางด้านสารตั้งต้นเพื่อให้ Q ลดลงจนเท่ากับ K', '2025-04-03 10:04:20', '2025-04-03 10:04:20'),
(610, 48, 'ข้อใดไม่ใช่ปัจจัยที่มีผลต่ออัตราการเกิดปฏิกิริยาเคมี?', 'ความเข้มข้นของสารตั้งต้น, อุณหภูมิ และตัวเร่งปฏิกิริยา เป็นปัจจัยที่มีผลต่ออัตราการเกิดปฏิกิริยาเคมีโดยตรง จำนวนโมลของผลิตภัณฑ์เป็นผลลัพธ์ที่เกิดขึ้นจากปฏิกิริยา ไม่ใช่ปัจจัยที่ส่งผลต่ออัตรา', '2025-04-03 10:04:20', '2025-04-03 10:04:20'),
(611, 49, 'สงครามโลกครั้งที่ 2 เริ่มต้นเมื่อใด?', 'สงครามโลกครั้งที่ 2 เริ่มต้นอย่างเป็นทางการเมื่อวันที่ 1 กันยายน 1939 เมื่อเยอรมนีบุกโปแลนด์', '2025-04-04 01:42:20', '2025-04-04 01:42:20'),
(612, 49, 'ประเทศใดเป็นผู้นำฝ่ายอักษะในช่วงสงครามโลกครั้งที่ 2?', 'เยอรมนีเป็นผู้นำฝ่ายอักษะ ซึ่งประกอบด้วย อิตาลี ญี่ปุ่น และประเทศอื่นๆ', '2025-04-04 01:42:20', '2025-04-04 01:42:20'),
(613, 49, 'การโจมตีเพิร์ลฮาร์เบอร์เกิดขึ้นเมื่อใด?', 'ญี่ปุ่นโจมตีเพิร์ลฮาร์เบอร์ในวันที่ 7 ธันวาคม 1941 ทำให้สหรัฐอเมริกาเข้าร่วมสงครามโลกครั้งที่ 2', '2025-04-04 01:42:20', '2025-04-04 01:42:20'),
(614, 49, 'ปฏิบัติการ Overlord หรือ D-Day คืออะไร?', 'D-Day คือวันที่ฝ่ายสัมพันธมิตรบุกครองนอร์มังดี (ฝรั่งเศส) ซึ่งอยู่ภายใต้การยึดครองของเยอรมนี', '2025-04-04 01:42:20', '2025-04-04 01:42:20'),
(615, 49, 'ระเบิดปรมาณูถูกทิ้งที่เมืองใดของญี่ปุ่น?', 'สหรัฐอเมริกาทิ้งระเบิดปรมาณูที่เมืองฮิโรชิมาและนางาซากิ ในเดือนสิงหาคม 1945', '2025-04-04 01:42:20', '2025-04-04 01:42:20'),
(616, 49, 'สนธิสัญญาใดที่ยุติสงครามโลกครั้งที่ 1 อย่างเป็นทางการ?', 'ไม่มีสนธิสัญญาเดียวที่ยุติสงครามโลกครั้งที่ 2 อย่างสมบูรณ์ มีการลงนามในสนธิสัญญาสันติภาพหลายฉบับกับประเทศต่างๆ ในช่วงเวลาต่างๆ กัน', '2025-04-04 01:42:20', '2025-04-04 01:42:20'),
(617, 49, 'ใครเป็นผู้นำสหภาพโซเวียตในช่วงสงครามโลกครั้งที่ 2?', 'โจเซฟ สตาลินเป็นผู้นำสหภาพโซเวียตในช่วงสงครามโลกครั้งที่ 2', '2025-04-04 01:42:20', '2025-04-04 01:42:20'),
(618, 49, 'เหตุการณ์ใดที่ถือว่าเป็นจุดเริ่มต้นของการฆ่าล้างเผ่าพันธุ์ชาวยิว (Holocaust)?', 'คืนแห่งการแตกหัก (Kristallnacht) ในปี 1938 เป็นเหตุการณ์สำคัญที่ถือว่าเป็นจุดเริ่มต้นของการฆ่าล้างเผ่าพันธุ์ชาวยิว', '2025-04-04 01:42:20', '2025-04-04 01:42:20'),
(619, 49, 'ใครเป็นประธานาธิบดีของสหรัฐอเมริกาในช่วงสงครามโลกครั้งที่ 2?', 'แฟรงคลิน ดี. รูสเวลต์เป็นประธานาธิบดีของสหรัฐอเมริกาในช่วงสงครามโลกครั้งที่ 2 จนกระทั่งเสียชีวิตในปี 1945 แฮร์รี เอส. ทรูแมนจึงขึ้นดำรงตำแหน่งแทน', '2025-04-04 01:42:20', '2025-04-04 01:42:20'),
(620, 49, 'สงครามโลกครั้งที่ 2 สิ้นสุดลงเมื่อใด?', 'สงครามโลกครั้งที่ 2 สิ้นสุดลงอย่างเป็นทางการเมื่อวันที่ 2 กันยายน 1945 เมื่อญี่ปุ่นยอมจำนน', '2025-04-04 01:42:20', '2025-04-04 01:42:20'),
(621, 50, 'ข้อใดคือวิธีการแสดงผลข้อความใน JavaScript ไปยัง Console?', 'console.log() เป็นคำสั่งที่ใช้สำหรับแสดงผลข้อมูลไปยัง Console ใน JavaScript', '2025-04-24 03:30:30', '2025-04-24 03:30:30'),
(622, 50, 'ตัวแปรชนิดใดที่ใช้เก็บค่าที่เป็นจริงหรือเท็จ (True/False) ใน JavaScript?', 'Boolean เป็นชนิดข้อมูลที่ใช้เก็บค่าที่เป็นจริง (true) หรือ เท็จ (false).', '2025-04-24 03:30:30', '2025-04-24 03:30:30'),
(623, 50, 'เครื่องหมายใดใช้สำหรับการเปรียบเทียบค่า \'เท่ากัน\' ใน JavaScript?', 'เครื่องหมาย \'==\' ใช้สำหรับเปรียบเทียบค่าว่าเท่ากันโดยไม่คำนึงถึงชนิดของข้อมูล (loose equality).', '2025-04-24 03:30:30', '2025-04-24 03:30:30'),
(624, 50, 'คำสั่งใดใช้ในการสร้างฟังก์ชันใน JavaScript?', 'คำสั่ง \'function\' ใช้ในการประกาศฟังก์ชันใน JavaScript', '2025-04-24 03:30:30', '2025-04-24 03:30:30'),
(625, 50, 'ข้อใดคือวิธีการเขียน Comment แบบบรรทัดเดียวใน JavaScript?', '// ใช้สำหรับเขียน comment แบบบรรทัดเดียวใน JavaScript', '2025-04-24 03:30:30', '2025-04-24 03:30:30'),
(626, 50, 'คำสั่งใดใช้ในการแสดงข้อความในกล่องข้อความ (Alert Box) ใน JavaScript?', 'alert() เป็นคำสั่งที่ใช้สำหรับแสดงข้อความในกล่องข้อความ (Alert Box) ใน JavaScript', '2025-04-24 03:30:30', '2025-04-24 03:30:30'),
(627, 50, 'ข้อใดคือวิธีที่ถูกต้องในการประกาศตัวแปรใน JavaScript?', 'การประกาศตัวแปรใน JavaScript ที่ถูกต้องคือใช้คำสั่ง \'var\', \'let\' หรือ \'const\' นำหน้าชื่อตัวแปร', '2025-04-24 03:30:30', '2025-04-24 03:30:30'),
(628, 50, 'ตัวดำเนินการใดใช้สำหรับการบวกเลขใน JavaScript?', '+ เป็นตัวดำเนินการสำหรับการบวกใน JavaScript', '2025-04-24 03:30:30', '2025-04-24 03:30:30'),
(629, 50, 'ฟังก์ชันใดใช้ในการแปลง String เป็น Integer ใน JavaScript?', 'parseInt() เป็นฟังก์ชันที่ใช้แปลง String เป็น Integer ใน JavaScript', '2025-04-24 03:30:30', '2025-04-24 03:30:30'),
(630, 50, 'คำสั่งใดใช้ในการตรวจสอบเงื่อนไขใน JavaScript?', 'คำสั่ง \'if\' ใช้ในการตรวจสอบเงื่อนไขและ execute code block ที่เกี่ยวข้องหากเงื่อนไขเป็นจริง', '2025-04-24 03:30:30', '2025-04-24 03:30:30');
